(243, 18, 5, 30, 'uploads/award_icons/68ceeb0704946_68c3bf0e0ef3e_1000103213.png', 'Geschmacks-Legende', '30 Mal die gleiche Sorte – du hast Geschichte geschrieben!', 450),
(244, 18, 6, 40, 'uploads/award_icons/68c3bf4b678e8_1000103214.png', 'Diamant der Kugel ', '40 Mal die gleiche Sorte – deine Hingabe funkelt wie ein Diamant.', 700),
(245, 44, 1, 2, 'uploads/award_icons/68ca52ef35951_ChatGPT Image 17. Sept. 2025, 08_18_49.png', '2 × 2 der Eisdielen', 'Du hast 2 Eisdielen jeweils 2-mal besucht – das kleine Einmaleins des Eisdielen-Genusses beginnt!', 50),
(246, 44, 2, 3, 'uploads/award_icons/68ca53b8021e0_ChatGPT Image 17. Sept. 2025, 08_19_52.png', '3 × 3 der Eisdielen', '3 Eisdielen, jeweils 3-mal besucht – du wirst zum Profi im Eisdielen-1 × 1!', 150),
(247, 44, 3, 4, 'uploads/award_icons/68ca539f5d864_ChatGPT Image 17. Sept. 2025, 08_21_45.png', '4 × 4 der Eisdielen', '4 Eisdielen, jeweils 4-mal besucht – deine Sammlung wächst bunt wie eine Eisvitrine!', 450),
(248, 44, 4, 5, 'uploads/award_icons/69b1055e20832_5x5Eisdielen.png', '5 × 5 der Eisdielen', '5 Eisdielen, jeweils 5-mal besucht – das Meisterstück im Eisdielen-1 × 1!', 500),
(249, 45, 1, 1, 'uploads/award_icons/68da385f50a33_ChatGPT Image 29. Sept. 2025, 09_37_36.png', 'Challenge Hunter', 'Du hast deine erste Challenge abgeschlossen! Was war das für ein Abenteuer. Eine Kariere als Eis-Agent steht dir bevor!', 150),
(250, 45, 2, 2, 'uploads/award_icons/68da38de35e46_2_Challenges.png', 'Challenge Hunter', 'Du hast bereits 2 Challenges abgeschlossen. Deine Agenten Ausbildung ist offiziell gestartet!', 150),
(251, 45, 3, 3, 'uploads/award_icons/68da398d1839d_3_Challenges.png', 'Challenge Hunter', 'Du hast bereits 3 Challenges abgeschlossen. Deine Agenten Ausbildung ist offiziell gestartet!', 150),
(252, 45, 4, 4, 'uploads/award_icons/68da399ba8772_4_Challenges.png', 'Challenge Hunter', 'Du hast bereits 4 Challenges abgeschlossen. Deine Agenten Ausbildung ist offiziell gestartet!', 150),
(253, 45, 5, 5, 'uploads/award_icons/68da3a54e206f_5_Challenges.png', 'Challenge Hunter', 'Du hast bereits 5 Challenges abgeschlossen. Deine Agenten Ausbildung ist offiziell gestartet!', 150),
(254, 45, 6, 6, 'uploads/award_icons/68da3a6218b95_6_Challenges.png', 'Challenge Hunter', 'Du hast bereits 6 Challenges abgeschlossen. Deine Agenten Ausbildung ist offiziell gestartet!', 150),
(255, 45, 7, 7, 'uploads/award_icons/68e2dbb157dcd_1000108900.png', '007 - Lizenz zum Eis', 'Ein besonderes Ehrenabzeichen im Retro-Comic-Stil für Agent:innen mit eisernem Durchhaltevermögen. Wer sieben Challenges abgeschlossen hat, trägt die „Lizenz zum Eis“ – cool, charmant und unerschütterlich wie James Bond selbst.', 150),
(256, 46, 2025, 5, 'uploads/award_icons/68d4ddd7bbcca_ChatGPT Image 25. Sept. 2025, 08_14_39.png', 'Herbst-Champion 2025', 'Du hast 5 oder mehr Eis im Herbst 2025 gegessen!', 150),
(257, 36, 24, 25, 'uploads/award_icons/68d5f3b8d673c_1000106078.png', '25 Wochen Eis-Streak', '25 Wochen – ein Vierteljahrhundert an Wochen mit Eis! Dieser Award steht für Beständigkeit, Freude und die Krönung einer langen süßen Reise.', 260),
(258, 36, 25, 26, 'uploads/award_icons/68d5f43fbffbf_1000106079.png', '26 Wochen Eis-Streak', 'Ein halbes Jahr ohne Unterbrechung – 26 Wochen voller Eis! Dieser Award markiert den legendären Meilenstein, der Beständigkeit und puren Genuss krönt.', 270),
(259, 36, 26, 27, 'uploads/award_icons/68d5f49d02f5e_1000106080.png', '27 Wochen Eis-Streak', '27 Wochen – mehr als ein halbes Jahr! Der Eis-Streak wächst über das Alltägliche hinaus und zeigt wahre Legenden-Ausdauer.', 280),
(260, 36, 27, 28, 'uploads/award_icons/68d6e47b210d7_ChatGPT Image 26. Sept. 2025, 21_07_22.png', '28 Wochen Eis-Streak', '28 Wochen – dieser Award würdigt pure Ausdauer und ein Feuerwerk an süßen Glücksmomenten.', 290),
(261, 36, 28, 29, 'uploads/award_icons/68d6e4e43707c_ChatGPT Image 26. Sept. 2025, 21_09_08.png', '29 Wochen Eis-Streak', '29 Wochen – ein fast ununterbrochener Strom von süßen Erfolgen. Der Eis-Streak hat längst mythische Dimensionen erreicht.', 300),
(262, 36, 29, 30, 'uploads/award_icons/68d6e54217aed_ChatGPT Image 26. Sept. 2025, 21_10_51.png', '30 Wochen Eis-Streak', '30 Wochen – ein legendärer Meilenstein! Ein Streak, der zeigt: wahre Helden bestehen nicht nur Rennen, sie genießen auch ihr Eis.', 310),
(263, 45, 8, 8, 'uploads/award_icons/68da3e222381a_8_Challenges.png', 'Eis-Drache – 8 Challenges besiegt', 'Sechs waren stark, sieben noch stärker – aber acht Challenges zu meistern, macht dich zum wahren Eis-Drachen-Bändiger!', 150),
(264, 45, 9, 9, 'uploads/award_icons/68da3e4ff093b_9_Challenges.png', 'Eis-Geheimoperation – 9 Challenges abgeschlossen', 'Für alle, die sich wie ein Top-Agent durch die Missionen geschlichen haben: unauffällig, clever und mit perfektem Timing. Dieses Abzeichen feiert deine „Geheimoperation im Eis-Einsatz', 150),
(265, 45, 10, 10, 'uploads/award_icons/68db9b228ec93_ChatGPT Image 30. Sept. 2025, 10_55_51.png', 'Eis-Galaxy – 10 Challenges erreicht', 'Ein intergalaktisches Abzeichen für alle, die ihre zehnte Challenge wie ein Weltraum-Pionier gemeistert haben. Dein Eis ist jetzt nicht mehr von dieser Welt.', 150),
(266, 45, 11, 11, 'uploads/award_icons/68db9b2d92d50_ChatGPT Image 30. Sept. 2025, 10_55_48.png', 'Eis-Paradies – 11 Challenges gemeistert', 'Elf Challenges geschafft – Zeit für Urlaub! Dieses Abzeichen zeigt, dass du dir dein Eis-Paradies redlich verdient hast.', 150),
(267, 43, 6, 53, 'uploads/award_icons/68dd0401cf5ad_ChatGPT Image 1. Okt. 2025, 12_32_52.png', 'Nutzer/in des Monats September 2025', 'Wahnsinn! Bereits den zweiten Monat in Folge beweist IceGoe voller Elan und Hingabe seine Leidenschaft fürs Eis-Schlecken! Mit 13 Check-ins im September hat er sich diesen Award mehr als verdient.', 250),
(268, 28, 6, 80, 'uploads/award_icons/68dff777d2f42_Mythos der Eis-Expeditionen.png', 'Mythos der Eis-Expeditionen', 'Mit 80 verschiedenen Eisdielen wirst du selbst zur Legende – dein Weg ist voller Geschichten.', 1000),
(269, 28, 7, 100, 'uploads/award_icons/68dff7c328d13_Großer Entdecker des Eises.png', 'Großer Entdecker des Eises', '100 verschiedene Eisdielen! Dein Name steht in den Chroniken der süßen Expeditionen.', 1250),
(270, 28, 8, 125, 'uploads/award_icons/68dff830f3494_Design ohne Titel (2).png', 'Unsterblicher Eiskosmopolit', '125 unterschiedliche Eisdielen besucht – du bist ein weltumspannender Entdecker, unsterblich in der Eisgeschichte.', 1500),
(271, 45, 12, 12, 'uploads/award_icons/68e4cde08e423_1000109194.png', 'Eis-Meister – 12 Challenges gemeistert', 'Zwölf Challenges gemeistert – Wie ein fleißiger Bildhauer sich durch den Stein meißelt, arbeitest du dich dich durch die Eisdielen!', 150),
(272, 45, 16, 16, 'uploads/award_icons/68e646a6eeb42_ChatGPT Image 8. Okt. 2025, 13_09_01.png', 'Eis-Ranger – 16 Challenges abgeschlosen', 'Sechzehn Challenges abgeschlossen – Wie ein harter Ranger, erarbeitest du dir Eis-Challenge für Eis-Challenge!', 150),
(273, 45, 17, 17, 'uploads/award_icons/68e64793ed63a_ChatGPT Image 8. Okt. 2025, 13_14_08.png', 'Der Vulkan-Eisjäger – 17 Challenges abgeschlosen', 'Siebzehn Challenges abgeschlossen – Die Jagd nach dem Eis-Vulkan ist abgeschlossen - du knallharter Hund weißt wie man Challenges abschließt!', 150),
(274, 45, 18, 18, 'uploads/award_icons/68f203a63f94d_ChatGPT Image 17. Okt. 2025, 10_50_32.png', 'Der Zeitreisende Eis-Agent – 18 Challenges abgeschlosen', 'Achtzehn Challenges abgeschlossen – Du bist durch Raum und Zeit gereist um 18 Challenges abzuschließen!', 150),
(275, 19, 28, 53, 'uploads/award_icons/68f2034825bf6_ChatGPT Image 17. Okt. 2025, 10_48_34.png', 'DONDURMA TÜRKİYE’DE', 'Für den Genuss eines Eises in der Türkei – dort, wo cremige Dondurma traditionell mit Show serviert wird. Ob an der Ägäis, am Bosporus oder in Kappadokien – dieser Award feiert deinen eiskalten Genussmoment zwischen Orient und Okzident.', 30),
(276, 19, 29, 54, 'uploads/award_icons/68f2067a3db84_Marokko.png', 'GLACE AU MAROC', 'Ein Eis im Königreich der Farben und Düfte – von den Souks Marrakechs bis zur Gischt des Atlantiks. Dieser Badge feiert deinen süßen Genussmoment in Marokko.', 30),
(277, 19, 30, 55, 'uploads/award_icons/68f206addf132_ChatGPT Image 17. Okt. 2025, 10_59_24.png', 'Moslajāt fī Miṣr', 'Eis unter der Sonne der Pharaonen – dieser Award ehrt dein eiskaltes Abenteuer in Ägypten. Zwischen Wüste, Nil und Pyramiden bleibt das Gelato ein königlicher Genuss.', 30),
(278, 36, 30, 31, 'uploads/award_icons/68f334be0ea46_1000112500.png', '31 Wochen Eis-Streak', '31 Wochen – das ist wahre Eis-Weisheit! Du hast längst das Alltägliche hinter dir gelassen und bist zum weisen Hüter der gefrorenen Kugeln aufgestiegen.', 320),
(279, 36, 31, 32, 'uploads/award_icons/68f3356b6101e_1000112502.png', '32 Wochen Eis-Streak', '32 Wochen – du bist auf dem Weg zur Legende! Jede Kugel erzählt eine Geschichte, jeder Check-in ein Kapitel deines eiskalten Abenteuers.', 330),
(280, 36, 32, 33, 'uploads/award_icons/68f33598a4665_1000112504.png', '33 Wochen Eis-Streak', 'Ein Schnapszahl an Wochen Eis! Dieser Orden ehrt deinen unerschütterlichen Glauben an den eiskalten Genuss – ein Symbol purer Ausdauer.', 340),
(281, 36, 33, 34, 'uploads/award_icons/68f3b7ee9814a_34 Wochen Eis-Streak Abzeichen.png', '34 Wochen Eis-Streak', '34 Wochen – du bist der Chronist der Eiszeit. Keine Waffel bleibt ungedreht, kein Geschmack ungetestet. Dieser Orden zelebriert deine ewige Neugier.', 350),
(282, 36, 34, 35, 'uploads/award_icons/68f3b849aee47_35 Wochen Eis-Streak Emblem.png', '35 Wochen Eis-Streak', '35 Wochen! Du bist ein lebendes Eisdenkmal. Dieser Award steht für meisterhafte Beständigkeit, Leidenschaft und eine Legende, die ihresgleichen sucht.', 360),
(283, 36, 35, 36, 'uploads/award_icons/68f3ba9279eeb_36 Wochen Eis-Streak Emblem.png', '36 Wochen Eis-Streak', '36 Wochen ununterbrochener Eisdielen-Glückseligkeit – du hast längst das „Eisjahr der Weisen“ erreicht. Dieser Orden steht für Disziplin, Genuss und unerschütterliche Leidenschaft.', 370),
(284, 36, 36, 37, 'uploads/award_icons/68f3ba9e4deae_37 Wochen Eis-Streak Emblem.png', '37 Wochen Eis-Streak', '37 Wochen – du bist ein Hüter des ewigen Sommers. Selbst Regen, Schnee oder Sturm können deinen Appetit auf Eis nicht trüben.', 380),
(285, 36, 37, 38, 'uploads/award_icons/68f3bb2b0d91d_38 Wochen Eis-Streak Emblem.png', '38 Wochen Eis-Streak', '38 Wochen voller Eistreue – du bist ein Wanderer zwischen Sorten und Zeiten. Dieser Award feiert deine unendliche Neugier und Hingabe.', 390),
(286, 36, 38, 39, 'uploads/award_icons/68f3bb7889f0a_39 Wochen Eis-Streak Emblem.png', '39 Wochen Eis-Streak', '39 Wochen – du hast das Reich des Eises fast erobert. Nur wenige haben so lange durchgehalten. Ein Symbol für wahre Genussausdauer.', 400),
(287, 36, 39, 40, 'uploads/award_icons/68f3bc2150332_40 Wochen Eis-Streak Emblem.png', '40 Wochen Eis-Streak', '40 Wochen ununterbrochen Eis – du bist eine Legende. Der „Eis-Kosmos“ kennt deinen Namen. Dieser Award ehrt eine fast übermenschliche Kontinuität.', 410),
(288, 47, 2026, 10, 'uploads/award_icons/68f474f276ed1_1000112657.png', 'Frühlings-Eis-Champion 2026', 'Du hast 10 oder mehr Eis im Frühling 2026 gegessen!', 150),
(289, 8, 6, 20, 'uploads/award_icons/68f478aeb54b6_1000112666.png', 'Der Meister der Karte', '20 Eisdielen eingetragen! Du kennst sie alle – von der kleinen Dorf-Eisdiele bis zum Großstadt-Kultladen. Ein wahrer Kartengestalter!', 400),
(290, 8, 7, 25, 'uploads/award_icons/68f478e293fd8_1000112667.png', 'Der Meister der Karte', '25 Eisdielen eingetragen! Du kennst sie alle – von der kleinen Dorf-Eisdiele bis zum Großstadt-Kultladen. Ein wahrer Kartengestalter!', 500),
(291, 8, 8, 30, 'uploads/award_icons/68f479909e064_1000112668.png', 'Der Legendäre Kartograph', '30 Eisdielen eingetragen! Deine Karte ist Legende – du hast die Eisdielen-Welt geprägt wie kein anderer!', 600),
(292, 29, 2, 50, 'uploads/award_icons/68f47a9065cec_1000112673.png', 'Bronze-Sammler', 'Du hast bereits 50 Awards gesammelt! Dein Sammelbuch beginnt zu glänzen – du bist auf dem besten Weg zum wahren Eis-Abenteurer.', 150),
(293, 29, 3, 100, 'uploads/award_icons/68f47ad22bb1f_1000112674.png', 'Goldener Award-Meister', '100 Awards – ein Meilenstein! Dein Sammelbuch strahlt in purem Gold und zeigt, dass du zu den engagiertesten Entdeckern der Ice-Welt gehörst.', 200),
(294, 29, 4, 150, 'uploads/award_icons/68f47b06200cc_1000112675.png', 'Legendärer Preisjäger', '150 Awards! Dein Sammelbuch funkelt wie ein Schatz. Kaum jemand hat so viele Erfolge eingefroren – du bist eine lebende Legende der Ice-App.', 250),
(295, 29, 5, 200, 'uploads/award_icons/68f47b38af432_1000112676.png', 'Großmeister der Auszeichnungen', '200 Awards gesammelt – ein epischer Moment! Dein Sammelbuch leuchtet wie ein Kronjuwel und erzählt von deiner unvergleichlichen Leidenschaft für Eis und Abenteuer.', 300),
(296, 2, 9, 150, 'uploads/award_icons/68f4af5ee89d5_150_Eis_eingecheckt.png', 'Der König der Kugeln', '150-mal Eis, 150-mal Triumph! Du hast das Reich der Eisdielen erobert und regierst über Waffeln, Sahne und Streusel. Dein Thron ist aus Eiskugeln, dein Zepter aus Waffeln – du bist die Legende der Eis-Republik', 1500),
(297, 2, 10, 200, 'uploads/award_icons/68f724c471f76_200_checkins.png', 'Unaufhaltbarer Eis-König', 'Zweihundert Checkins, unzählige Sorten – du herrschst über das Reich des Eises wie kein anderer. Eine Legende auf zwei Rädern mit einem unstillbaren Appetit auf Genuss!', 2000),
(298, 7, 8, 125, 'uploads/award_icons/68f4b22e84c58_125_Preise_gemeldet.png', 'Eispreis-Stratege', '125 Preise im System – du analysierst, vergleichst und formst die Zukunft der Eiskugel-Ökonomie.', 700),
(299, 7, 9, 150, 'uploads/award_icons/68f4b25e951be_150_Preise_gemeldet.png', 'Markt-Maestro', '150 Preise gemeldet – du dirigierst die Eisökonomie wie ein Maestro seine Sinfonie.', 800),
(300, 7, 10, 200, 'uploads/award_icons/68f4b2856e284_200_Preise_gemeldet.png', 'Preis-Baron', '200 Preise! Du bist der Hochadel der Preisjäger – dein Name flüstert sich von Waffel zu Waffel.', 900),
(301, 7, 11, 250, 'uploads/award_icons/68f4b2a488a8e_250_Preise_gemeldet.png', 'Eispreis-Imperator', '250 Meldungen – du regierst über das Reich der Kugelpreise. Kein Beleg entgeht deinem Blick!', 1000),
(302, 33, 4, 50, 'uploads/award_icons/68f7cf86d6233_ChatGPT Image 21. Okt. 2025, 20_22_47.png', 'Wortarchitekt', '50 meisterhafte Rezensionen mit mehr als 250 Zeichen– du formst Worte wie Eisskulpturen: präzise, elegant und voller Tiefe. Deine Texte bauen Brücken zwischen Genuss und Kunst – du bist der Architekt der Worte', 500),
(303, 23, 7, 200, 'uploads/award_icons/68f7d753a5d09_ultimate_gourmet_cyclist.png', 'Der Ultimative GourmetCyclist', 'Über 200 mal hast du die Eisdielen per Fahrrad besucht, damit bist du bist der Inbegriff des Eisradelns!\r\nDu bist der ultimative GourmetCyclist!', 1000),
(304, 23, 6, 100, 'uploads/award_icons/68f7d7d1a5133_ChatGPT Image 21. Okt. 2025, 20_52_04.png', 'Der Gefrorene Champion', 'Dein Name ist Legende du hast bereits über 100 mal Eisdielen mit dem Fahrrad besucht und damit den Asphalt bezwungen und den Sommer verewigt!', 500),
(308, 48, 1, 1, 'uploads/award_icons/68fbd8b6b3579_Vier_Jahreszeiten_Award.png', 'Vier Jahreszeiten Eis-Schlecker', 'Du hast in allen vier Jahreszeiten Engagement beim Eis-Schleckern gezeigt!', 350),
(309, 49, 1, 4, 'uploads/award_icons/68fbd9e0d36b6_Multimobiler_Genießer.png', 'Multimobiler Genießer', 'Du hast bereits auf vier verschiedene Arten zur Eisdiele gefunden – ob zu Fuß, auf zwei Rädern, mit Motor oder Schienen: Du bist der wahre Mobilitäts-Gourmet!', 120),
(310, 49, 2, 5, 'uploads/award_icons/68fbd9fb21e63_Weltenbummler_aus_Eis.png', 'Der Weltenbummler auf Eis', 'Fünf verschiedene Wege führten dich schon zum Eis – du bist ein wahrer Abenteurer auf Genuss-Mission! Kein Verkehrsmittel ist dir zu fremd, wenn es um Gelato geht.', 200),
(311, 50, 1, 1, 'uploads/award_icons/68fda73f0168e_1000113323.png', 'Gemeinsam schmeckt’s besser', 'Dein erstes Eis in Gesellschaft – weil geteiltes Eis doppelt schmeckt!', 100),
(312, 50, 2, 5, 'uploads/award_icons/68fda99ab6073_1000113329.png', 'Sozialer Schlecker', 'Du hast schon mehrere Eisschleck-Abenteuer in Gesellschaft erlebt. Teamgeist zahlt sich aus!', 200),
(313, 50, 3, 10, 'uploads/award_icons/68fda9af535bf_1000113330.png', 'Gruppen-Gourmet', 'Du bist ein Profi im gemeinsamen Eisgenuss – wahre Genussmomente in Gesellschaft!	', 400),
(314, 50, 4, 25, 'uploads/award_icons/68fda9e819c11_1000113331.png', 'Eis-Komplizen', 'So viele gemeinsame Eis-Erlebnisse! Du bist der Anführer einer süßen Bande.', 700),
(315, 50, 5, 50, 'uploads/award_icons/68fdaa49b4775_1000113333.png', 'Der Soziale Schleckmeister', 'Du bist das Herz jeder Eistruppe – ohne dich schmeckt’s nur halb so gut!', 1000),
(316, 51, 1, 3, 'uploads/award_icons/6900615337871_Eis-Trio.png', 'Eis-Trio', 'Drei Schlecker auf einer Mission – ein unschlagbares Team!', 200),
(317, 51, 2, 5, 'uploads/award_icons/6900615b5c7ca_ChatGPT Image 28. Okt. 2025, 07_20_06.png', 'Eis-Gang', 'Ihr wart als Gang von 5 oder mehr Personen auf Eis-Mission – ihr seid nicht zu stoppen!', 400),
(318, 51, 3, 8, 'uploads/award_icons/69006332463e0_ChatGPT Image 28. Okt. 2025, 07_30_35.png', 'Eis-Parade', 'Eine bunte, feiernde Gruppe von 8 oder mehr Eis-Enthusiasten seid ihr durch die Straßen gezogen  – Eis in der Hand, Lächeln im Gesicht.', 700),
(319, 51, 4, 12, 'uploads/award_icons/6900627647557_ChatGPT Image 28. Okt. 2025, 07_20_24.png', 'Der Schleck-Clan', 'Ihr habt mit 12 oder mehr Personen die Eisdiele gestürmt – eine Legendäre Schleck-Aktion!', 1000),
(320, 43, 7, 53, 'uploads/award_icons/6905cebee5470_User_of_the_month_october25.png', 'Nutzer/in des Monats Oktober 2025', 'Dreifach-Schlecker! IceGoe holt sich den dritten Titel in Serie, ist der erste Nutzer der mit 19 Check-ins im Oktober mit TheGourmetCyclist gleich zieht und knackt die 50er-Grenze!', 250),
(321, 45, 19, 19, 'uploads/award_icons/690a4e9aeb03b_1000114908.png', 'Der Eis-Expeditionsleiter – 19 Challenges abgeschlosen', '19 Challenges – du hast das Unbekannte erforscht, die kältesten Kugeln und die seltensten Sorten entdeckt. Deine Abenteuerlust kennt keine Grenzen – du bist der Entdecker des Gefrorenen.', 150),
(322, 45, 20, 20, 'uploads/award_icons/690a4f1a1d7c0_1000114910.png', 'Der Eis-Blockbuster – 20 Challenges abgeschlosen', 'Licht, Kamera, Action! Du bist der Hauptdarsteller deiner eigenen Eis-Saga. 20 Challenges – das ist kein Zufall, das ist Hollywood-Reife Leistung!', 150),
(323, 45, 21, 21, 'uploads/award_icons/690a4f88b815b_1000114912.png', 'Der Eis-Piratenkapitän – 21 Challenges abgeschlosen', 'Mit 21 Challenges hast du die sieben Geschmacksmeere erobert! Kein Becher zu groß, kein Waffelberg zu hoch – du bist der Captain des kühlen Genusses.', 150),
(324, 45, 22, 22, 'uploads/award_icons/690a4ff3cc821_1000114914.png', 'Der Eis-Magier – 22 Challenges abgeschlosen', '22 Challenges – du beherrschst die magische Kunst des Gefrorenen. Mit einem Handschwung zauberst du Kugeln, Softeis und Becher aus purer Energie herbei.', 150),
(325, 45, 23, 23, 'uploads/award_icons/690a50cd85c04_1000114916.png', 'Der Galaktische Eis-Entdecker – 23 Challenges abgeschlosen', 'Grenzen existieren für dich nicht. 23 Challenges später fliegst du durch das Universum des Genusses – auf Mission Eis Infinity!', 150),
(326, 45, 24, 24, 'uploads/award_icons/690a528aa52df_1000114918.png', 'Der Gentleman des Eises – 24 Challenges abgeschlosen', 'Mit 24 abgeschlossenen Challenges beweist du Stil, Klasse und kühlen Kopf. Du bist der Inbegriff des geschmackvollen Abenteurers – charmant, zielstrebig und immer mit perfektem Schliff serviert.', 150),
(327, 45, 25, 25, 'uploads/award_icons/690a530d32fce_1000114920.png', 'Der Highspeed-Schlecker – 25 Challenges abgeschlosen', 'Du rast von Eisdiele zu Eisdiele, immer auf der Überholspur des Geschmacks. 25 Challenges – pure Geschwindigkeit trifft auf süße Perfektion.', 150),
(328, 19, 31, 27, 'uploads/award_icons/69124b4e1d681_Award_Malta.png', 'ĠELAT F’MALTA', 'Ein Eis auf der sonnigen Insel Malta – zwischen historischen Gassen, türkisblauen Buchten und mediterranem Flair. Dieser Award feiert deinen süßen Moment im Herzen des Mittelmeers!', 30),
(329, 19, 32, 7, 'uploads/award_icons/69124d72289c5_Award_Andorra.png', 'GELAT ANDORRÀ', 'Ein Eis zwischen den Pyrenäen – wer hier schleckt, genießt frische Bergluft und süßen Geschmack in einem kleinen Land mit großem Charme.', 30),
(330, 19, 33, 14, 'uploads/award_icons/69124d9dbdb05_Award_Estland.png', 'JÄÄTIS EESTIS', 'Eis im hohen Norden! Dieser Award ehrt deinen Genussmoment zwischen Ostsee, Kopfsteinpflaster und digitaler Zukunft in Estland.', 30),
(331, 19, 34, 16, 'uploads/award_icons/69124ddebcf2a_Award_Georgien.png', 'Naqini Sakartveloshi', 'Ein Eis in Georgien – wo Berge, Meer und Wein zusammentreffen. Dieser Award feiert deinen Genussmoment zwischen Tradition und Gastfreundschaft.', 30),
(332, 19, 35, 23, 'uploads/award_icons/69124eb83e43f_Award_Lettland.png', 'SALDĒJUMS LATVIJĀ', 'Eis in Lettland – ob am Ostseestrand von Jūrmala oder in der Jugendstilmetropole Riga. Ein goldener Moment im Baltikum!', 30),
(333, 19, 36, 18, 'uploads/award_icons/69124e597f067_Award_Irland.png', 'ICE IN IRELAND', 'Ein Eis im Land der grünen Hügel und herzlichen Menschen – dieser Badge würdigt deinen cremigen Genuss auf der Smaragdinsel.', 30),
(334, 45, 13, 13, 'uploads/award_icons/6916433b76434_Eisentdecker.png', 'Der Eis-Entdecker – 13 Challenges gemeistert', 'Dreizehn Challenges gemeistert – Wie ein fabelhafter Entdecker, erkundest du Eisdielen und neue Geschmäcker!', 150),
(335, 45, 14, 14, 'uploads/award_icons/691643f8e02f5_GALAKTISCHES EIS-ABENTEUEUR 14 CHALLENGES ABGESCCHLOSSEN.png', 'Galaktisches Eis-Abenteuer – 14 Challenges gemeistert', 'Vierzehn Challenges gemeistert – Schon zu durchs halbe Universum gehuscht auf der Suche nach Eisdielen!', 150),
(336, 45, 15, 15, 'uploads/award_icons/6916444b417ca_Eiskoenig.png', 'Der Eis-König – 15 Challenges gemeistert', 'Fünfzehn Challenges gemeistert – Ein Reich für den Eis-König!', 150),
(337, 52, 1, 23, 'uploads/award_icons/69284d07767c7_1000118599.png', 'Gewinner der Instagram Foto-Challenge 2025', 'Aus 16 Bildern setzt sich Holzmichl mit seinem Bild bei der Instagram Foto-Challende erfolgreich durch und sichert sich den Meistertitel', 1000),
(338, 43, 8, 53, 'uploads/award_icons/693b295df3b93_Nutzer_des_Monats_Nov25.png', 'Nutzer/in des Monats November 2025', 'IceGoe macht es wieder! Nicht nur seit 14 Wochen jede Woche Eis, sondern auch seit 4 Monaten klebt er bereits auf dem Thron des Nutzer des Monats, ganz ähnlich wie Karamelleis.', 250),
(339, 53, 1, 1, 'uploads/award_icons/694685b467ad2_694652736c5c9_1000120745.png', 'Zwischen den Jahren 2025', '🎄✨ Schön, dass du zwischen den Jahren dabei warst!\r\nDieser Award feiert deinen Besuch in der Ice-App zum Jahresausklang.\r\nWir wünschen dir ein fröhliches Fest und einen guten Rutsch! 🎆🍦', 35),
(340, 53, 2, 2, 'uploads/award_icons/694652d8557c3_1000120746.png', 'Eis zwischen den Jahren 2025', '🎆🍦 Zwischen den Jahren eingecheckt!\r\nDieser Award feiert dein Eis-Check-In in der Weihnachts- und Silvesterzeit.\r\nDanke fürs Mitmachen – frohe Feiertage und einen guten Rutsch! ✨🎄', 50),
(341, 53, 3, 3, 'uploads/award_icons/69477cdceee84_1000120963.png', 'Ostern 2026 – Dabei gewesen', '🐣🍦 Frohe Ostern!\r\nDieser Award ist eine kleine frühlingshafte Belohnung dafür, dass du die Ice-App zu Ostern geöffnet hast.\r\nGenieße die Feiertage und lass es dir schmecken! 🌸✨', 35),
(342, 53, 4, 4, 'uploads/award_icons/69477d32a2594_1000120966.png', 'Ostern 2026 – Eis eingecheckt', '🐰🍦 Oster-Check-In geschafft!\r\nDieser Award feiert dein Eis-Check-In während der Osterzeit.\r\nDanke fürs Mitmachen – frohe Ostern und weiterhin viel Eisgenuss! 🌸✨', 50),
(343, 53, 5, 5, 'uploads/award_icons/694781526b5a2_1000120968.png', 'Zwischen den Jahren 2026', '🎄✨ Schön, dass du zwischen den Jahren dabei warst!\r\nDieser Award feiert deinen Besuch in der Ice-App zum Jahresausklang.\r\nWir wünschen dir ein fröhliches Fest und einen guten Rutsch! 🎆🍦', 35),
(344, 53, 6, 6, 'uploads/award_icons/6947816c43b71_1000120970.png', 'Eis zwischen den Jahren 2026', '🎆🍦 Zwischen den Jahren eingecheckt!\r\nDieser Award feiert dein Eis-Check-In in der Weihnachts- und Silvesterzeit.\r\nDanke fürs Mitmachen – frohe Feiertage und einen guten Rutsch! ✨🎄', 50),
(345, 54, 1, 1, 'uploads/award_icons/694bdde985236_ChatGPT Image 24. Dez. 2025, 13_31_22.png', 'Entdecker der geheimen Weihnachts-Eis-Werkstatt', 'Geheimnis gelüftet! Du hast 2025 die versteckte Eis-Werkstatt des Weihnachtsmanns entdeckt.', 150),
(346, 36, 40, 41, 'uploads/award_icons/694fd8bc33ad9_ChatGPT Image 27. Dez. 2025, 14_00_44.png', '41 Wochen Eis-Streak', '41 Wochen Eis-Streak – du hast bewiesen, dass selbst die Zeit dem Eis nicht widerstehen kann. Woche für Woche fließt cremiger Genuss durch die Sanduhr deiner Beständigkeit. Nur wahre Eis-Chronisten erreichen diesen Meilenstein.', 420),
(347, 36, 41, 42, 'uploads/award_icons/694fd9d0310cb_ChatGPT Image 27. Dez. 2025, 14_06_11.png', '42 Wochen Eis-Streak', '42 Wochen Eis-Streak – alles ist im Gleichgewicht. Geschmack, Geduld und Leidenschaft haben sich zu einer perfekten Eis-Harmonie verbunden. Dieser Award steht für Ordnung im Chaos der Sorten.', 430),
(348, 36, 42, 43, 'uploads/award_icons/694fd953b1132_ChatGPT Image 27. Dez. 2025, 14_04_06.png', '43 Wochen Eis-Streak', '43 Wochen Eis-Streak – du hast das nächste Level erreicht. Das Eis selbst scheint dir den Weg zu weisen. Wer so lange durchhält, liest die Zukunft in Kugeln und Waffeln.', 440),
(349, 43, 9, 40, 'uploads/award_icons/6955c1689d3c9_1000122828.png', 'Nutzer/in des Monats Dezember 2025', 'Anton checkte zwei mal im Duo ein, sichert sich jede Menge Awards und damit auch den Titel \"Nutzer des Monats Dezember 2025\" 🎉', 250),
(350, 43, 10, 8, 'uploads/award_icons/697fb2cb897c1_1000125953.png', 'Nutzer/in des Monats Januar 2026', 'Enkiboy schnabbulierte zwei mal Eis in zwei verschiedenen Ländern und sichert sich damit auch den Titel \"Nutzer des Monats Januar 2026\" 🎉', 250),
(351, 54, 3, 3, 'uploads/award_icons/6981e282e0fb6_olympia.png', 'Eis-Winterolympiade 2026 ', 'Du hast eine Spielstätte der Winterolympiade 2026 entdeckt und sicherst dir ein paar Punkte für die Eis-Winterolympiade.', 10),
(352, 55, 1, 10, 'uploads/award_icons/6984974901ee9_Olympic_bronze.png', 'Bronze in der Eis-Winterolympiade 2026', 'Wie ein Wirbelwind startest du in die Eis-Winterolympiade!\r\nProfil gepflegt, App gestartet – der erste Schritt Richtung olympischen Eis-Gold. ❄️🍦', 50),
(353, 55, 2, 40, 'uploads/award_icons/698497bc6d8f6_Olympic_silber.png', 'Silber in der Eis-Winterolympiade 2026', 'Mit eiskalter Präzision sammelst du XP und holst dir Silber am Eis-Schießstand!\r\nOlympisches Silber bei der Eis-Winterolympiade 2026! 🥈❄️', 100),
(354, 55, 3, 100, 'uploads/award_icons/698498895fad6_Olympic_gold.png', 'Olympiasieger:in des Eises 2026', 'Eiskalt ziehst du durch und springst zu olympischen Gold!\r\nDu hast den olympischen Eis-Fünfkampf gemeistert. 🥇🍦❄️', 250),
(355, 43, 11, 53, 'uploads/award_icons/69a35a533bbff_1000129843.png', 'Nutzer/in des Monats Februar 2026', 'Ice-Goe brilliert bei der Eis-Winterolympiade, macht in Prag einen Schleckmarathon mit 6 besuchten Eisdielen an nur einem Tag und sichert sich somit der Titel Nutzer des Monats Februar 2026! 🏅', 250),
(356, 56, 1, 0, 'uploads/award_icons/69a945671b4d1_the_taste_of_chemitz_clouds.png', 'Vorschau: The Taste Of Chemnitz', 'Du hast den limitierten TheTasteOfChemnitz Award gefunden. Checke bis zum 31. Mai \'26 bei drei verschiedenen Chemnitzer Eisdielen ein und zeig so dass du ein echter Foodie bist und schalte den Award frei.', 0),
(357, 56, 2, 1, 'uploads/award_icons/69a945ce3be87_the_taste_of_chemnitz.png', 'The Taste Of Chemnitz', 'Mit diesem limitierten Award zeigst du, dass du ein echter Chemnitzer Foodie bist und Chemnitz kulinarisch auf diversen Ebenen erkundest!', 250),
(358, 57, 1, 100, 'uploads/award_icons/69aa8e56aa859_birthday_bronze.png', 'Birthday Supporter', 'Die Ice-App wird 1 Jahr alt und du bist Teil der großen Party!', 40),
(359, 57, 2, 200, 'uploads/award_icons/69aa8ed34b6d8_birthday_silver.png', 'Birthday Champion', 'Die Ice-App wird 1 Jahr alt und du lässt es so richtig krachen!', 150),
(360, 57, 3, 500, 'uploads/award_icons/69aa8f2a0dd6b_birthday_gold.png', 'Birthday Legend', 'Du hast bei der Geburtstagsparty der Ice-App vollkommen abgeliefert und totalen Legendenstatus erreicht. Die Partycrew blickt zu dir auf!', 500),
(361, 19, 37, 56, 'uploads/award_icons/69aac79eed1e7_Usbekistan.png', 'MUZQAYMOQ O‘ZBEKISTONDA', 'Ein Eis auf der Seidenstraße! Dieser Award feiert deinen süßen Genussmoment in Usbekistan – zwischen türkisblauen Kuppeln, historischen Medresen und den Märkten von Samarkand.', 30),
(362, 45, 26, 26, 'uploads/award_icons/69af7e5ec503a_1000131250.png', 'Der Eis-Detektiv – 26 Challenges abgeschlosen', 'Nichts entgeht deinem Blick! Mit 26 abgeschlossenen Challenges hast du jede Spur verfolgt und jedes Rätsel gelöst. Wo andere nur eine Eisdiele sehen, erkennst du eine Mission.', 150),
(363, 45, 27, 27, 'uploads/award_icons/69af7f0dd9e3e_1000131252.png', 'Der Eis-Geheimagent – 27 Challenges abgeschlosen', 'Deine Mission: Eis entdecken, genießen und Herausforderungen meistern. 27 Challenges später bist du ein echter Spezialagent des Geschmacks.', 150),
(364, 45, 28, 28, 'uploads/award_icons/69af7f7f294fe_1000131254.png', 'Der Eis-Actionheld – 28 Challenges abgeschlosen', 'Explosionen, Verfolgungsjagden und spektakuläre Eisfunde – du meisterst jede Herausforderung mit Stil. 28 Challenges zeigen: Du bist der Held der Eis-Abenteuer.', 150),
(365, 45, 29, 29, 'uploads/award_icons/69afb4922d6d4_29_Challenges_abgeschlossen.png', 'Der Eis-Actionheld – 29 Challenges abgeschlosen', 'Du hast Karten gelesen, Geheimnisse gelüftet und die seltensten Eis-Schätze entdeckt. Mit 29 Challenges bist du einer der größten Schatzjäger der Ice-App.', 150),
(366, 45, 30, 30, 'uploads/award_icons/69afb4b185838_30_Challenges_abgeschlossen.png', 'Der Eis-Actionheld – 30 Challenges abgeschlosen', '30 Challenges – das ist kein Abenteuer mehr, das ist Geschichte! Dein Name wird unter Eisliebhabern weitergegeben wie eine Legende.', 150),
(367, 58, 1, 2, 'uploads/award_icons/69afb5ae83957_Der Eis-Doppelsturm.png', 'Der Eis-Doppelsturm', 'Zwei Challenges. Ein Tag. Unaufhaltsam.\r\nDu bist wie ein Sturm durch die Eiswelt gezogen und hast doppelt zugeschlagen. Nur wenige schaffen dieses Tempo.', 300),
(368, 58, 2, 3, 'uploads/award_icons/69afb5b8953a7_Der Eis-Triumph.png', 'Der Eis-Triumph', 'Drei Challenges an einem einzigen Tag – das ist kein Glück, das ist Legende.\r\nDu hast die Eiswelt erobert und bist in die höchste Liga der Ice-App aufgestiegen.', 600),
(369, 44, 5, 6, 'uploads/award_icons/69b10496d22a6_5x5Eisdielen.png', '6 × 6 der Eisdielen', '6 Eisdielen jeweils 6-mal besucht – du beherrschst das große Einmaleins der Eisdielen! Deine Eisreise wird zur echten Sammlung.', 600),
(370, 44, 6, 7, 'uploads/award_icons/69b106506a2e7_7x7Eisdielen.png', '7 × 7 der Eisdielen', '7 Eisdielen jeweils 7-mal besucht – du bist eine echte Eislegende! Das Einmaleins der Eisdielen liegt dir inzwischen im Blut.', 800),
(371, 19, 38, 57, 'uploads/award_icons/69b1bd54a1199_ChatGPT Image 11. März 2026, 20_06_33.png', 'ICE IN THE BVI', 'Ein Eis im Paradies! Dieser Award würdigt deinen süßen Genussmoment auf den Britischen Jungferninseln – zwischen weißen Sandstränden, türkisblauem Wasser und karibischer Leichtigkeit.', 30);
