(1853, 52, 'checkin_mention', NULL, 863, 'yannickr.t hat angegeben, mit dir Eis gegessen zu haben. Checke jetzt dein Eis ein.', 1, '2026-03-11 18:36:24', '{\"by_user\": \"31\", \"shop_id\": \"649\", \"username\": \"yannickr.t\", \"shop_name\": \"The Baths\", \"checkin_id\": \"863\", \"checkin_mention_id\": \"49\"}');
INSERT INTO `bewertungen` (`id`, `eisdiele_id`, `nutzer_id`, `geschmack`, `kugelgroesse`, `waffel`, `auswahl`, `beschreibung`, `erstellt_am`, `zuletzt_bearbeitet_am`, `is_on_site`) VALUES
(1, 16, 1, 4.6, 4.0, 3.5, 16, '', '2025-03-14 08:27:11', NULL, 0),
(2, 18, 1, 4.9, 1.7, 3.5, 8, 'Ich hatte eine Kugel gebrannte Mandeln. Das Eis war sehr lecker, vorallem durch die Stückchen gebrannte Mandel die noch oben drauf gestreut waren, allerdings für 2€ war die Kugel relativ klein.', '2025-03-16 09:52:01', NULL, 0),
(3, 17, 1, NULL, NULL, NULL, 26, 'Kartenzahlung ab 10€ möglich.', '2025-03-14 08:27:11', NULL, 0),
(4, 10, 1, 4.8, 4.1, 4.7, 20, 'Direkt auf dem Altmarkt von Hohenstein-Ernstthal gelegen mit großer Sonnenterasse und einigen Sitzmöglichkeiten außen.\r\nHier gibt es auch Cocktails etc.', '2025-03-17 18:36:58', NULL, 0),
(5, 5, 1, 4.5, 3.7, 1.0, 26, 'Rüllis Eismanufaktur stellt eine Vielzahl leckerer, teils ausgefallene Sorten her.\r\nSie beliefern mit ihrem Eis auch einige Imbisse, Bäckerein etc.\r\n\r\nDie Lage direkt am Parkplatz ist nicht die schönste, zumal Sitzmöglichkeiten fehlen. Dafür nah am Premium Radweg gelegen.', '2025-03-26 21:09:53', NULL, 0),
(6, 6, 1, 3.9, 2.4, 1.5, 16, '', '2025-03-20 18:52:20', NULL, 0),
(7, 36, 1, NULL, NULL, NULL, 9, '', '2025-03-21 12:06:35', NULL, 0),
(8, 39, 1, 4.9, 3.3, 4.5, 20, 'Ich hatte eine Kugel \'Kalter Hund\', die war sehr lecker und für 1,50€ auch angemessen groß. Die Waffel war sehr knusprig und lecker. \nInsgesamt hatte die Eisdiele eine gute Auswahl an Sorten.', '2025-03-23 17:48:39', NULL, 0),
(10, 1, 1, 4.7, 4.5, 3.8, 14, 'Sehr leckeres Eis, die Kugeln sind ordentlich groß und den Preis wert.\r\n\r\nEs lohnt sich 2 Kugeln oder mehr zu nehmen, ab dann gibt es eine besser schmeckende knusprige Waffel. Bei einer Kugel bekommt man leider nur eine kleine \'pappige\'.', '2025-03-24 16:44:36', NULL, 0),
(11, 32, 1, 4.6, 2.0, 4.3, 18, 'Das Eis war lecker und hat intensiv nach Eierlikör geschmeckt. Für 2€ war die Kugel schon sehr klein. Die Waffel war war schlank und knusprig, fast etwas zu knusprig für meinen Geschmack. Auffällig ist, dass ich Eierlikör-Nougat bei einer anderen Eisdiele schon hatte wo es exakt gleich geschmeckt hat und die gleichen Waffeln verwendet wurden.', '2025-03-24 17:50:13', NULL, 0),
(12, 11, 1, 4.8, 4.2, 4.7, 16, 'Sehr leckeres Eis in einer super großen leckeren Waffel. Aber nur wenn man 2 Kugeln oder mehr nimmt, bei einer Kugel bekommt man eine pappige Waffel. Die Auswahl umfasst jetzt weniger ausgefallene Sorten, aber trotzdem alles lecker. Besonders die Sorte Milchreis kann ich empfehlen.', '2025-03-27 08:57:04', '2026-03-10 19:02:07', 0),
(17, 26, 1, 4.3, 3.0, 4.5, 20, 'Ich hatte eine Kugel Mango und eine Kugel Cookies. Die Kugel Mango war sehr groß, die Cookie Kugel hingegen eher klein. Insgesamt schon sehr solide, aber es könnten zum Beispiel mehr Cookie Stückchen im Eis sein.', '2025-03-27 15:15:06', NULL, 0),
(18, 47, 1, 3.2, 2.7, 1.8, 7, 'Sehr günstiges Eis, allerdings nur die Sorten Erdbeere, Vanille, Schoko und Himmelblau für 1€ und die Sorten haben eher nach billig Discounter Eis geschmeckt. Die restlichen 3 Sorten kosteten 1,50€, wobei Heidelbeere recht lecker war. Die Kugeln waren eher klein und die Eiswaffel nicht gut.', '2025-03-28 15:55:33', NULL, 0),
(19, 55, 1, 4.6, 4.1, 4.8, 18, 'Eine gute Auswahl an leckeren Sorten. Ich hatte eine Kugel Erdbeerkäsekuchen, welche ziemlich gut geschmeckt hat.\nFür 1,50 € in Verbindung mit einer sehr leckeren, knusprigen Waffel eine wirkliche Empfehlung.', '2025-03-28 17:05:17', NULL, 0),
(20, 58, 1, 2.5, 1.7, 3.0, 7, 'Sehr liebevolles Café mit wirklich tollen, leckeren Kuchen und Torten zu sehr fairen Preisen, aber leider war das Eis nicht wirklich gut. Es hatten sich schon Kristalle gebildet, was vielleicht daran liegen mag, dass es insgesamt wenig besucht ist. Sehr schade :(', '2025-03-30 11:23:34', NULL, 0),
(22, 22, 1, 4.8, 4.4, 4.7, 18, 'Ich hatte eine Kugel Schoko-Praline. Die war äußerst lecker, mit vielen Nuss / Pralinen Stückchen. Und für 1,30€ die Kugel äußerst groß.\nDie Waffel war auch sehr lecker und angenehm groß.', '2025-04-02 04:04:01', NULL, 0),
(25, 31, 1, 4.7, 4.3, 3.5, 2, 'Beliebter Softeisstand auf dem Markt in Kietscher. Es gab zwei verschiedene gemischte Softeis zur Auswahl in klein und groß für 1,50 bzw. 2,50 € und für 20 Cent Aufpreis gab es Streusel auf das Eis.', '2025-04-02 14:55:24', NULL, 0),
(26, 2, 1, NULL, NULL, NULL, 20, 'Direkt am Radweg gelegen liegt das Eiscafé Kohlebunker.\r\nDie Öffnungszeiten wurden die letzten Jahre immer weiter ungekürzt und das Wetter muss schon gut sein, damit die Eisdiele geöffnet hat.', '2025-04-03 11:35:39', NULL, 0),
(28, 20, 1, NULL, NULL, NULL, 14, '', '2025-04-03 14:16:26', NULL, 0),
(29, 9, 1, NULL, NULL, NULL, 8, '', '2025-04-03 14:32:36', NULL, 0),
(30, 61, 1, NULL, NULL, NULL, 16, '', '2025-04-03 14:54:47', NULL, 0),
(31, 63, 1, NULL, NULL, NULL, 25, 'Sehr gemütliches Lokal, mit nettem Personal. Ich war im Dezember dort, da gab es draußen einen kleinen Bereich für Glühwein etx.Das Eis wird hier noch selbst hergestellt und es gibt viele leckere verschiedene Sorten.👌🏼😊\r\n\r\nMan kann auch für 1,50€ nur eine kleine Kugel Eis wählen. Das finde ich ein fair.', '2025-04-04 04:59:06', NULL, 0),
(32, 46, 1, 4.9, 4.9, 4.5, 13, 'Ich hatte eine Kugel Erdnuss und eine Kugel weiße Schokolade, die Portion war wirklich riesig und geschmacklich wahnsinnig lecker. Die Waffel war geschmacklich auch Top, allerdings gab es bei anderen Eisdielen schon etwas größere Waffeln.\nMit noch ein paar Schokostückchen z.bsp. in den Eiskugeln und größeren Waffeln hätte es die perfekte Bewertung gegeben.', '2025-04-04 12:46:24', NULL, 0),
(38, 69, 1, NULL, NULL, NULL, 6, '', '2025-04-05 16:49:59', NULL, 0),
(39, 71, 1, 4.8, 4.0, 4.2, 18, 'Das Eis war sehr lecker und enthielt einige Schoko- / Pralinenstückchen. Die Portion war für 2,00€ angemessen und die Waffel war auch recht lecker aber klein. Andere Kunden mit ebenfalls nur einer Kugel Eis haben teilweise andere (größere) Waffeln erhalten.', '2025-04-06 11:58:24', NULL, 0),
(54, 29, 1, 5.0, 3.7, 3.5, 12, 'Ich hatte eine Kugel Marzipan und\neine Kugel Cookies, beide waren\nsuper lecker und viel zu schnell\nverputzt. Bemerkenswert war die Cremigkeit vom Eis.\nDas Lokal ist sehr niedlich und\nscheint privat betrieben zu sein.', '2025-04-07 16:24:22', NULL, 0),
(56, 40, 1, 4.8, 4.5, 3.0, 31, 'Meine Kugel salziges Karamell war geschmacklich vorzüglich und hatte eine wunderbar cremige Konsistenz.\nEine riesige Auswahl an teils ausgefallene Sorten runden das Angebot ab.\nLediglich bei der einfachen Waffel gibt es Luft nach oben.', '2025-04-08 14:16:56', NULL, 0),
(60, 37, 1, 4.6, 3.5, 4.8, 6, 'Kremeeis Wildpreiselbeere aus eigener Herstellung aus Milch, Eiern und Zucker', '2025-04-08 15:15:56', NULL, 0),
(65, 81, 1, 4.9, 4.5, 4.7, 16, '', '2025-04-09 07:22:27', NULL, 0),
(66, 82, 1, NULL, NULL, NULL, 30, '', '2025-04-09 07:26:37', NULL, 0),
(68, 86, 1, 2.4, 2.4, 2.0, 14, 'Eine Kugel Straciatella und eine Kugel Pfirsich-Maracuja.\nDie Kugel Straciatella hatte zwar viele Schokostückchen aber beide Kugeln haben wässrig geschmeckt, waren eher klein und geben in Verbindung mit einer pappigen Waffel ein schlechtes Gesamtbild ab.', '2025-04-09 14:42:11', NULL, 0),
(74, 83, 1, NULL, NULL, NULL, 16, '', '2025-04-12 09:09:49', NULL, 0),
(75, 72, 1, 4.5, 4.4, 4.8, 19, 'Ich hatte eine Kugel Amarena-Kirsch und eine Cookies. Sehr cremig aber hätte etwas fruchtiger bzw. \"keksiger\" sein können.\nInsgesamt ein sehr solides Eis. In Verbindung mit der großen, knusprigen Waffel macht man nichts verkehrt.\n', '2025-04-12 09:46:53', NULL, 0),
(76, 100, 1, 3.4, 3.9, 1.9, 9, 'Ich hatte eine Kugel Noggereis,  welche geschmacklich ganz gut war, aber zu hart / kalt. Meine Verlobte hatte eine Kugel Tiramisu, welche wiederum zu weich war.\nDafür gibt es sehr leckeren Kaffee und gutes Bier.', '2025-04-13 11:53:34', NULL, 0),
(95, 101, 1, 5.0, 4.1, 2.3, 14, 'Alle 3 Kugeln Cookies, Salted Caramel und Brombeer Holunder waren super lecker, hatten eine cremige Konsistenz und vor allem hatten sie viele Cookie, Karamell bzw. Fruchtstückchen. Die Papp-Waffel war leider das einzige Manko. Ansonsten Top Top Top!', '2025-04-14 14:04:41', NULL, 0),
(97, 98, 1, 4.7, 4.1, 4.2, 24, 'Super leckeres, sehr günstiges Eis und eine große Auswahl an Sorten, wobei alle Sorten den gleichen Preis kosten.\nSchade dass ich mit meiner Bestellung von 4 Kugeln zwar eine größere aber nicht so knusprige Waffel wie die anderen bekommen habe.', '2025-04-16 14:34:21', NULL, 0),
(103, 10, 4, 4.2, 4.8, 4.8, NULL, 'Machste nix verkehrt. Schön schokoladig. Ab und zu ein Eiskristall in der Mitte.', '2025-04-20 12:22:39', NULL, 0),
(105, 9, 4, 4.4, 2.5, 4.5, NULL, '', '2025-04-21 13:20:39', NULL, 0),
(106, 115, 3, 4.7, 4.5, 3.2, 2, 'Bei meinem Besuch im Eisgarten an der Kaßbergauffahrt ließ ich mir ein Schoko-Vanille-Softeis schmecken. Überzeugen konnte das Eis durch die Kombination aus der für Softeis üblichen cremigen Konsistenz sowie durch seinen angenehmen Geschmack. Eine eher schlechtere Bewertung erhielt die sehr einfache Waffel. Das Angebot an Eissorten ist sehr überschaubar, was aber bei Softeis keine Überraschung ist. Punkten kann der Eisgarten ebenfalls durch seine kleine anschließende Grünfläche sowie einige Sitzmöglichkeiten, die zum Verweilen einladen. Für Softeis-Liebhaber einen Besuch wert!', '2025-04-22 11:24:51', NULL, 0),
(108, 59, 1, 4.8, 4.5, 2.3, 10, 'Gut im Ort versteckt, hat mich die kleine aber feine Eckeisdiele doch positiv überrascht.\r\nEs gibt Softeis, Kugeleis und Eisbecher im Angebot.\r\nMeine Kugeln Zimt und Malaga waren beide sehr lecker, intensiv von Geschmack und relativ groß.\r\nDazu ein günstiger Preis von 1,20€ pro Kugel.\r\nLediglich die kleine \"Papp\"Waffel sorgt mal wieder für Abzüge.', '2025-04-22 14:45:49', NULL, 0),
(113, 118, 1, 4.6, 5.0, 4.6, 30, 'Eine super Auswahl von ca. 30 Sorten, davon ziemlich viele ausgefallene. Die Kugeln waren die größten die ich bis jetzt jemals bekommen habe. Das Eis war lecker, aber bei der Geschmacksintensität ist noch bisschen Raum nach oben. Insgesamt eine große Empfehlung.', '2025-04-26 00:17:09', NULL, 0),
(118, 75, 1, NULL, NULL, NULL, 3, 'Hier gibt es einen Automaten, wo man Vanille-Softeis pur, mit Erdbeerfruchtzubereitung oder Soße mit Schokogeschmack bekommen kann.', '2025-04-27 13:45:01', NULL, 0),
(120, 123, 2, 4.0, 3.0, 3.0, 22, 'Ich hatte eine Kugel Waldmeister, war ganz okay mal zur Abwechslung. Gibt eine überraschen große Auswahl zwischen Fruchtiges und Schokoladiges/Cookies etc. Nur die Kugelgröße hätte für den Preis besser sein können (1,90€)', '2025-04-27 15:33:12', NULL, 0),
(121, 32, 3, 4.6, 4.0, 4.5, NULL, 'Ich entschied mich bei meinem Besuch am Milchkännchen für die Premiumsorte Joghurt-Sanddorn, womit ich definitiv eine gute Wahl traf. Der Geschmack wirkt ausgefallen/aufregend und vertraut zugleich. Auch mit seiner cremigen Konsistenz wusste das Eis zu überzeugen, abgerundet von einer leckeren und knusprigen Waffel. Eine Premiumsorte hat jedoch mit 2,20€ einen Preis, dem die Kugelgröße nicht ganz gerecht wird. Bei einem anschließenden Spaziergang am Schloßteich schmeckt das Eis gleich nochmal besser. ', '2025-04-27 16:30:16', NULL, 0),
(122, 124, 4, 4.5, 5.0, 4.0, 12, 'Waffel nicht getestet. \nEiskugeln waren sehr groß \n', '2025-04-27 17:44:38', NULL, 0),
(123, 121, 1, 3.4, 1.7, 3.5, 2, 'Das Schoko Vanille Softeis hat etwas wie Zott Monte Joghurt geschmeckt nur etwas weniger intensiv. Die größte war angemessen und die Waffel wie bei Softeis fast immer eher pappig.', '2025-04-27 18:56:38', NULL, 0),
(125, 125, 7, 4.0, 5.0, 5.0, 1, 'Es gibt am WALKTEICH neben zahlreichen Imbisssnacks nur Softeis.\nBei diesem kann man wählen, ob man Vanille, Schokolade oder die Mischung haben möchte.\nDie Größe fand ich dem Preis angemessen.\nHervorzuheben ist der wunderbare Außenbereich mit tollen Sitzmöglichkeiten und Schattenplätzen am Teich. \nEs gibt zudem eine große Speisenauswahl und eine reichhaltige Getränkekarte.', '2025-04-27 19:28:12', NULL, 0),
(126, 42, 1, 4.6, 4.7, 4.6, 18, 'Das Eiscafé Piccolo bietet eine große Auswahl leckerer Sorten an, wobei jede Sorte 1,60€ kostet.\nMeine Sorten Himbeere und Nougat konnten überzeugen und die Portionen waren für den Preis sehr gut.\nDer Verkäufer war sehr nett und plauderte etwas mit mir. 😅', '2025-04-28 14:35:01', NULL, 0),
(130, 92, 1, 4.9, 4.5, 4.3, 16, 'Die Eisdiele Saneto hat ein breites Sortiment an Kugel- und Softeis, wobei es auch viele ehere besondere Sorten gibt. Premiumsorten kosten mit 2,20€ dabei 20cent mehr als die restlichen Sorten.\n\nIch hab mich für Eierlikör-Nougat und Quark-Zitrone entschieden, welche beide sehr sahniges, intensiv und lecker schmeckend waren.\nBesonders der Eierlikör Geschmack kam gut zur Geltung\nAls weitere Besonderheit gibt es einen 24/7 Automat an dem man sich abgepacktes Eis holen kann.\n', '2025-04-29 14:26:23', NULL, 0),
(138, 14, 1, NULL, NULL, NULL, 13, 'Hier gibt es täglich wechselndes Softeis.\nFür 50cent Aufpreis gibt es besondere (farbige) Waffeln die wohl auch verschiedene Geschmäcker haben.', '2025-04-30 14:24:58', NULL, 0),
(139, 106, 1, 5.0, 4.9, 4.7, 21, 'Ein tolles Eiscafé mit einer süßen kleinen Sitzecke auf dem Bürgersteig. Es gibt eine große Auswahl an ausgefallenen Sorten. Ich hatte je eine Kugel Kirsch-Schoko und Baileys. Das Eis war fantastisch lecker, besonders die Kugel Schoko-Kirsch glänzte mit einer Vielzahl an ganzen Kirschen und vielen Schokostückchen. 😍 Ein absolutes Geschmackshighlight, besser kann Eis nicht schmecken! \nEs gibt auch Bubble Waffels im Angebot', '2025-04-30 15:03:43', NULL, 0),
(142, 126, 1, 4.4, 3.0, 3.5, 16, 'Die Kugel Cheesecake-Waldbeere war lecker und mit einigen kleinen Beeren drinnen.\nIch habe mir für 40 Cent Aufpreis eine Schokowaffel gegönnt, welche sich nicht gelohnt hat. Die Waffel war selber etwas pappig und die Schokolade und Streusel haben den Geschmack nicht so aufgewertet wie erhofft. ', '2025-05-01 15:38:54', NULL, 0),
(144, 126, 4, 4.1, 4.2, 4.2, 18, 'Absolutes durchschnittliches Eis. Für ein schnelles auf die Hand bei Bedarf geeignet!', '2025-05-01 18:39:45', NULL, 0),
(145, 12, 7, 4.0, 5.0, 3.5, 5, 'In Hübschmanns Eislädl gibt es immer drei Sorten frisches Softeis. Das Angebot wechselt dabei stets.\nDen Klassiker Schoko-Vanille bieten sie immer an. Dazu kommen dann noch zwei ausgefallenere Sorten. Heute waren es noch Erdbeere-Vanille und Schoko-Kokos.\nZudem gibt es viele verschiedene Sorten Softeis im Becher, dieses ist jedoch nicht „frisch gezapft“.\nAb dem großen Softeis gibt es eine leckere knusprige Waffel.\nEmpfehlenswert sind auch die Eisbecher (kleine aber feine Auswahl!) und die Eisschokolade bzw. -kaffee.\nWas ich heute zum ersten Mal gesehen habe: Man kann sich das Softeis auch in selbst mitgebrachte Behälter abfüllen lassen.', '2025-05-01 19:06:04', NULL, 0),
(146, 132, 2, 4.4, 4.8, 4.8, 40, 'Ein echt schönes Eiscafe in der Innenstadt von Pirna. Es gibt eine große Auswahl an Kugeleis (ca. 40 Sorten) aber auch an Softeis (z.B. Mango oder Kokos). Leider nur Selbstbedienung aber dafür sehr empfehlenswert (gibt zB auch Crepes)', '2025-05-02 04:52:41', NULL, 0),
(147, 45, 1, 3.9, 4.0, 4.0, 8, 'Das Kugeleis ist Standard und schmeckt okay, der Preis von 1€ pro Kugel macht es interessant.\nBemerkenswert ist das Softeis, die kleine Portion für 1€ war super lecker und für den Preis auch sehr groß!', '2025-05-02 11:22:56', NULL, 0),
(148, 128, 10, 4.0, 4.0, NULL, 12, 'Solides Eis, aber mit Abstrichen im Service und der Präsentation\n\nNach längerer Zeit haben wir der Eisdiele wieder einen Besuch abgestattet – das schöne Wetter lud einfach zu einem Eisbecher ein. Anschließend ging es für einen Spaziergang an den nahegelegenen See.\n\nDas Eis war geschmacklich gut, die Portionen angemessen, und es hat uns allen geschmeckt. Besonders gefallen haben uns der Nougatbecher (mit vier Nougatstückchen, Sahne und passenden Eissorten), der Bananensplit (mit frischen Bananenscheiben, Sahne sowie Vanille- und Bananeneis), der Jogurettenbecher (wobei statt Joguretteneis leider Joghurteis verwendet wurde) und ein Kinderbecher. Insgesamt haben wir für vier Becher 36 € bezahlt – ein aus unserer Sicht etwas hoher Preis, vor allem, da Sortenänderungen mit 1 € extra pro Becher berechnet werden. Positiv zu erwähnen ist, dass Kartenzahlung möglich ist.\n\nIm Vergleich zu früher hat die Eisdiele jedoch etwas nachgelassen. Es gibt keine Bedienung mehr am Tisch – man bestellt an der Theke und trägt das Eis selbst zum Platz. Auch die Präsentation der Eisbecher war eher schlicht und wenig liebevoll gestaltet. Gerade bei den Preisen hätten wir uns hier mehr Mühe und Kreativität gewünscht.\n\nEin großer Pluspunkt ist jedoch der tolle Spielplatz am örtlichen See: Kinder erwartet dort eine Seilbahn, eine Rollenrutsche (Tipp: Brotkiste oder Sitzunterlage selbst mitbringen) sowie zahlreiche Klettermöglichkeiten – ein echtes Highlight für Familien.\n\nFazit: Wer ein solides Eis in guter Lage genießen möchte, wird hier fündig. Wer aber Wert auf freundlichen Service und optisch ansprechende Eisbecher legt, könnte etwas enttäuscht sein. Mit etwas mehr Liebe zum Detail wäre deutlich mehr möglich – das tolle Freizeitangebot in der Nähe gleicht jedoch einiges wieder aus.\n', '2025-05-02 11:31:58', NULL, 0),
(149, 134, 1, 4.7, 4.3, 4.7, 17, 'Eine sehr große leckere Waffel, die Kugel Butterkeks war sehr lecker und hatte einige Keks und Schokostückchen.', '2025-05-02 12:05:10', NULL, 0),
(155, 135, 1, 4.0, 2.7, 1.0, 10, 'Das Eis war leider nichts besonderes. Ich liebe eigentlich Weiße Schokolade, aber geschmacklich hätte man deutlich mehr raus holen können. Dazu kommt noch die wirklich unterirdische Waffel. Tipp: lieber nebenan bei Eiscafé Ys für 10 Cent mehr ein deutlich besseres Eis kaufen.', '2025-05-02 15:19:49', NULL, 0),
(157, 133, 1, 2.1, 2.7, 3.0, 3, 'Hier gibt es nur Softeis, welches abgepackt aus dem Tiefkühler geholt wird und durch eine Softeispresse gedrückt wird.\nIst halt keine Eisdiele oder Café sondern ein Gemischtwarenladen.\nUm den akuten Eishunger zu stillen schon ganz gut, ein Geschmackshighlight sollte man hier nicht erwarten.', '2025-05-02 15:28:30', NULL, 0),
(160, 136, 1, 4.5, 4.0, NULL, 5, 'Hier gibt es nur Eisbecher zur Auswahl. Mein Eisbecher Orion für 80czk war sehr lecker und für den Preis auch gut groß.', '2025-05-03 11:32:13', NULL, 0),
(161, 137, 11, 4.0, 1.0, 1.0, 8, '', '2025-05-05 07:03:57', NULL, 0),
(162, 46, 5, 4.9, 4.9, NULL, NULL, 'Top Eisdiele in richtig guter Lage, perfekt für einen kurzen Stopp. Freundliches Team, alles sauber und entspannt. Man merkt, dass hier mit Liebe gearbeitet wird. ', '2025-05-05 09:26:18', NULL, 0),
(163, 118, 5, 4.8, 4.0, NULL, 25, 'Eis war lecker, Kugeln durchschnittlich groß. Es gab auch ein paar ausgefallenere Sorten wie „Dubai Chocolate“. Auswahl insgesamt sehr gut. Der Besitzer wirkte eher mäßig freundlich, aber an und für sich trotzdem empfehlenswert.', '2025-05-05 09:31:54', NULL, 0),
(166, 139, 5, 4.5, 3.5, NULL, 15, 'Wirklich leckeres Sorbet, Milchreis eher durchschnittlich. Man zahlt hier klar auch für die Lage.', '2025-05-06 18:26:51', NULL, 0),
(174, 115, 1, 4.0, 3.5, 2.8, 2, 'Hier gibt es ausschließlich Softeis in zwei Geschmackskombinationen.\n\nSo cremig das Softeis ist, so schnell war es auch verputzt.\nBei Waffel und Größe muss ich ein paar Abzüge machen und der Geschmack war etwas künstlich, aber ich vermute damit muss man bei Erdbeer Softeis rechnen.', '2025-05-10 12:38:00', NULL, 0),
(177, 125, 2, 4.4, 3.8, 4.0, 1, 'Sehr schöner Zwischenstopp. Direkt am Teich mit vielen Sitzmöglichkeiten. Außerdem gibt\'s dort auch viel sonstige Verpflegung. Softeis leider nur eine Größe und nur Schoko Vanille. War aber solide. Die Waffel ist knusprig und im Stile einer kugeleiswaffel', '2025-05-10 13:25:42', NULL, 0),
(179, 162, 11, 4.5, 4.0, 4.0, 10, 'Eisdiele mit einer kleinen Wiese und Sitz sowie Spielmöglichkeiten. Manchmal seltsame Kunden. Sehr Kinderfreundlich. Topings möglich', '2025-05-10 18:52:44', NULL, 0),
(181, 117, 1, 4.6, 4.8, 3.8, 16, 'Eine sehr große Kugel Eis, der Gummibären Geschmack war interessant und lecker und tatsächlich fällt mir keine bessere Beschreibung ein als \'hat authentisch nach Gummibärchen geschmeckt\' 😅 Die Waffel ist eher im Mittelfeld an zu siedeln.', '2025-05-12 15:41:50', NULL, 0),
(184, 28, 1, 4.4, 4.3, 5.0, 6, 'Ein sehr ausgefallenes Konzept. Bei n\'Eis zapfen wählt man einen Becher oder eine Waffel und kann sich dann beliebig 6 Sorten Softeis und einer großen Auswahl an Toppings ein Eis (oder auch eher einen Eisbecher) zusammen stellen.\nNeben Softeis kann man sich wohl auch Hot-Dogs zusammenstellen. Das teste ich aber erst, sobald ich eine App für Hot-Dogs entwickelt habe :D', '2025-05-13 14:31:59', NULL, 0),
(188, 163, 8, 3.6, 3.6, 4.2, 7, 'Es gab keine Eistheke - man bekommt die Sorten genannt und muss sich blind entscheiden. \n\nGeschmacklich i.O. wobei das Erdbeereis etwas künstlich geschmeckt hat - Schokolade hingegen war durchaus lecker. \n\nBonus war die Riesenwaffel in der die zwei Kugeln aber etwas verloren aussahen. \n', '2025-05-14 19:53:06', NULL, 0),
(189, 165, 1, NULL, NULL, NULL, 24, '\"Marschner\'s Eiscafé\", kein anderes Lokal hat wohl in der Region so eine Bekanntheit und einen Ruhm für Eisgenuss.\r\nUm so herber war der Schock, als die Eisdiele letztes Jahr auf einmal geschlossen hatte und die Zukunft ungewiss war.\r\nHeute (am 15.05) öffnete die Eisdiele mit dem alten Betreiber wieder ihre Pforten!\r\nEs gibt eine große Auswahl an ausgefallenen Sorten und ein Preis System von 1,80€ / 2,00€ / 2,20€ pro Kugel.\r\n\r\nSchön ist der neu angelegt Park in unmittelbarer Nähe.', '2025-05-15 11:48:10', NULL, 0),
(191, 145, 1, NULL, NULL, NULL, 16, 'Hier gibt es selbstgemachtes Eis und Torte / Kuchen. Das Angebot wechselt immer mal.\r\nDraußen ist eine gemütliche Terrasse zum verweilen.\r\n\r\nEin kleiner nicht allzu frequentierter Geheimtipp, direkt in der Nähe vom Schloss Lichtenwald 😎👌🏼', '2025-05-18 11:31:11', '2026-03-07 12:28:25', 0),
(192, 9, 25, NULL, NULL, NULL, NULL, 'Gutes Softeis! Es ist erhältlich in den Sorten Schoko-Vanille oder Erdbeer-Vanille. Sitzgelegenheiten gibt es draußen & drinnen. ', '2025-05-19 17:14:02', NULL, 0),
(194, 60, 2, NULL, NULL, NULL, 22, 'Schöner belebter Außenbereich und auch zum Reinsetzen. Nun zum Eis:\nSo muss Mango schmecken! Vielfältiges Angebot und sehr lecker. Die Waffel ist nicht billig, aber auch nicht zu trocken, war mir sehr angenehm. Leider nur etwas kleine Kugeln', '2025-05-20 19:32:49', NULL, 0),
(196, 175, 2, NULL, NULL, NULL, 7, 'Sehr lecker italienisches Eis! Gute Kugelgröße. Ich hatte Fragola😜 einfach mega schön hier!', '2025-05-25 11:28:20', NULL, 0),
(197, 176, 2, NULL, NULL, NULL, 3, 'Passt schon, aber kein Tourziel unbedingt wert', '2025-05-26 11:16:14', NULL, 0),
(198, 177, 8, NULL, NULL, NULL, 19, 'Leckeres Eis mit vielen interessanten Sorten, ein Bonus sind die schwarzen Waffeln ', '2025-05-26 15:07:11', NULL, 0),
(199, 56, 1, NULL, NULL, NULL, 18, 'Sehr schönes Café in toller Lage mit großem Außensitzbereich und einer tollen Auswahl an Eissorten 😍\nDie Gegend lädt zu einem Ausflug ein und das Café ist auf jeden Fall einen Besuch wert.', '2025-05-27 13:45:41', NULL, 0),
(200, 89, 33, NULL, NULL, NULL, 20, '', '2025-05-27 16:41:31', NULL, 0),
(201, 184, 32, NULL, NULL, NULL, NULL, 'Hier findest du verschiedene Sorten Softeis, aber auch ein tolles Angebot an Bubblewaffeln. Askir Fresh besitzt eine kleine Sitzecke, auch einen kleinen Radständer. Da sich der Große Garten gleich in der Nähe befindet empfiehlt es sich meiner Meinung nach, vorallem an warmen Sommertagen, sich dann dort ein gemütliches Plätzchen auf einer Wiese oder Bank zu suchen. Im Sommer kann es hier gerade bei den Bubblewaffeln zu ein bisschen Wartezeit kommen. ', '2025-05-28 05:19:51', NULL, 0),
(202, 170, 1, NULL, NULL, NULL, 10, 'Ziemlich lange anstehen, da die Personen am Ausschank doch nicht die flottesten waren.\r\nAnsonsten gibt es Herzhafte Snacks, wie Bowu, Wiener etc, Bier, Kaffee und Kuchen zu laufen.', '2025-05-28 05:23:08', NULL, 0),
(203, 112, 1, NULL, NULL, NULL, 4, 'Hier gibt es lediglich Softeis, dafür 4 verschiedene Sorten und mit verschiedenen Toppings und Saußen. Es gibt auch immer vegane Optionen.\r\nDirekt anliegend ist der Gerhard-Hauptmann Platz ein schöner Park mit Spielplatz.', '2025-05-28 11:24:47', NULL, 0),
(205, 4, 1, NULL, NULL, NULL, 1, 'Es gibt hier immer nur eine Sorte im Angebot, diese wechselt aber ständig.\nSehr schöner Gartenbereich der zum Verweilen einlädt, nette Verkäuferin die mir auch schon öfters die Trinkflaschen fürs Fahrrad aufgefüllt hat.', '2025-05-29 13:57:37', NULL, 0),
(206, 21, 1, NULL, NULL, NULL, 13, 'Eine gute Auswahl ausgefallener Sorten, die man so nicht überall findet. Dazu gibt es auch Softeis, Eisbecher und einen schönen Außenbereich wo man sein Eis gemütlich in der Sonne essen kann.', '2025-05-30 14:17:39', NULL, 0),
(207, 193, 2, NULL, NULL, NULL, 2, 'Hier gibt\'s zum Bubbletea auch Softeis. Entweder Schoko/Vanille oder Melone/Mango. Als kleines Früchtchen hatte ich das zweite. Hatte im Becher bestellt, die Waffel sah standardmäßig für Softeis aus. Das kleine Eis an sich hatte eine okay Größe für den Preis. Geschmacklich wars nicht überragend, aber auch nicht schlecht.', '2025-05-30 16:23:56', NULL, 0),
(208, 194, 39, NULL, NULL, NULL, 16, 'Sehr nettes Personal, super leckere Eissorten mit großer Auswahl', '2025-05-30 16:39:38', NULL, 0),
(211, 195, 41, NULL, NULL, NULL, 10, 'Lieblingscafé am Nordufer des Cosspudener See, im Torhaus des Kees\'schen Parks. Eis draußen am Pavillon aber auch drinnen. Überschaubares Kugel-Angebot aber immer neue, ausgefallene Kreationen.\nViele weitere leckere Speisen, großes phantastisches Kuchenangebot. Herrlicher Außenbereich für jede Witterung, auch Rastplatz für mitgebrachte Speisen, drinnen zwei Etagen, jeden Tag 2 Suppen, großartiges Frühstücksbuffet.\nIm Winter frische Waffeln.', '2025-05-30 22:19:22', NULL, 0),
(213, 150, 1, NULL, NULL, NULL, 18, 'Gelegen im Erdgeschoss eines Plattenbaus liegt das Eiscafé Roßberg. Draußen gibt es einen schönen und großen Sitzbereich im Grünen.', '2025-05-31 12:03:53', NULL, 0),
(215, 199, 40, NULL, NULL, NULL, 2, 'Tolles Eis!', '2025-06-01 15:37:35', NULL, 0),
(216, 200, 40, NULL, NULL, NULL, NULL, 'Stracciatella und Caramel Sorbet, sehr köstlich', '2025-06-01 19:10:58', NULL, 0),
(221, 201, 40, NULL, NULL, NULL, NULL, 'Super', '2025-06-01 19:16:06', NULL, 0),
(223, 202, 2, NULL, NULL, NULL, 1, 'Sehr solides Softeis, leider nur Schoko/Vanille, aber dennoch sehr lecker und sahnig bzw. Cremig. Waffel ist Standard für softeis. Die Größe ist für das Geld auch iO :)', '2025-06-01 19:59:10', NULL, 0),
(224, 204, 41, NULL, NULL, NULL, 14, 'Selbstbedienung.\nSoft- und Kugeleis mit Liebe produziert. \nGetränke, Shakes und Eisbecher\n\nGroßer Freisitz mit Tischen und Bänken. Bäume und Pavillon sorgen für Schatten.\n\nVor dem Zaun gibt es einen Eisautomaten!\n', '2025-06-02 14:49:18', NULL, 0),
(225, 205, 1, NULL, NULL, NULL, 16, 'Kleines Lokal mit Eis-Fenster zur Straße.\nEs gibt Kugeleis und Softeis.\nDas Kugeleis hat mich nicht ganz überzeugt, das Softeis was die Kunden hinter mir hatten sah aber sehr gut aus, das werde ich wohl noch mal probieren 🤓', '2025-06-03 13:57:32', NULL, 0),
(226, 3, 1, NULL, NULL, NULL, 14, 'Kleines uriges Lokal, direkt am Marktplatz. Unter anderem gibt es Schwarzbier-Eis.\n', '2025-06-03 15:16:49', NULL, 0),
(230, 65, 1, NULL, NULL, NULL, 21, 'Ein großes altes Gebäude mit Eisdiele. Alles etwas in die Jahre gekommen und es gibt einen Spendenaufruf zum Erhalt des Gebäudes.\r\nAber die Eisdiele ist absolut genial, super Preise, sehr leckeres Eis, große Portionen, tolle Sorten und nettes Personal.\r\nEinen Besuch wert!\r\n\r\nVom 29. September bis 4. April in der Winterpause.', '2025-06-04 07:12:42', NULL, 0),
(234, 35, 1, NULL, NULL, NULL, 19, 'Direkt am Marktplatz in Chemnitz gelegen, gibt es hier Kaffee, Kuchen und auch einen Straßenverlauf für Eis.\n', '2025-06-04 12:39:55', NULL, 0),
(239, 207, 2, NULL, NULL, NULL, 6, 'Kleine Eisdiele in der Gaststätte beim Campingplatz. Ich hatte eine Kugel Schoko und eine Erdbeere. Geschmacklich ganz solide, aber für den Preis ziemlich klein :/', '2025-06-08 13:33:22', NULL, 0),
(240, 47, 2, NULL, NULL, NULL, 2, 'Es gibt hier zwar auch Kugeleis, ich würde aber nur das Softeis empfehlen. Das ist mega lecker und auch wirklich groß für den kleinen Preis', '2025-06-14 13:18:26', NULL, 0),
(241, 70, 1, NULL, NULL, NULL, 18, 'Schön gelegener Bäcker / Café mit Recht großen Eisangebot.\nWenn man draußen sitze hat man Blick auf die Wolkensteiner Schweiz.', '2025-06-15 12:39:46', NULL, 0),
(242, 213, 1, NULL, NULL, NULL, 19, 'Schön gelegener Bäcker, wo es neben leckeren Eis auch gute Kuchen zu vernünftigen Preisen gibt. 👍🏼', '2025-06-17 13:54:48', NULL, 0),
(249, 223, 1, NULL, NULL, NULL, 14, 'Die Bäckerei liegt direkt am Markt, es gibt ein Straßenverkaufsfenster für Eis, sowie einige Sitzgruppen draußen. Es gibt 12 Sorten Eis und 2 Sorten Softeis.', '2025-06-18 18:35:53', NULL, 0),
(250, 222, 1, NULL, NULL, NULL, 18, 'In einer Seitengasse gelegen gibt es hier ein Verkaufsfenster für Straßenverkauf.', '2025-06-18 18:38:24', NULL, 0),
(251, 234, 49, NULL, NULL, NULL, 12, '', '2025-06-20 15:22:55', NULL, 0),
(253, 249, 31, NULL, NULL, NULL, 16, 'sehr moderne Location mit extrem leckeren Eis und großen Kugeln ', '2025-06-23 07:37:01', NULL, 0),
(254, 254, 31, NULL, NULL, NULL, 24, 'Eisdiele befindet sich sehr zentral in der Stadt. Es gibt viele exklusive Eissorten. Der Geschmack ist sehr gut. Preis/Leistung passt nicht ganz. ', '2025-06-24 08:13:01', NULL, 0),
(255, 89, 1, NULL, NULL, NULL, 12, 'Die Sorten sehen alle toll aus, mit vielen Frucht- oder Schokostückchen. 😋\nDirekt auf dem Markt gelegen mit großem Außensitzbereich und auch Innen gibt es viele Sitzplätze.', '2025-06-24 14:35:50', NULL, 0),
(256, 258, 48, NULL, NULL, NULL, 24, 'Gute Lage im Büroviertel am Fluss. Bedienung sehr nett. Man kann auch mit Karte bezahlen ', '2025-06-24 16:14:42', NULL, 0),
(257, 259, 52, NULL, NULL, NULL, 2, 'Sehr schön eingerichtet, nettes Personal und es gibt leckere Eisbecher mit einer Vielzahl von Toppings', '2025-06-24 19:02:08', NULL, 0),
(258, 249, 52, NULL, NULL, NULL, NULL, 'Der wohl schönste eingerichtete Eisladen auf Zypern, viele Sorten und große Kugeln ', '2025-06-24 19:03:30', NULL, 0),
(259, 99, 1, NULL, NULL, NULL, 2, 'Hier gibt es täglich eine andere Sorte Softeis. Entweder pur oder gemischt mit Vanille.\nDie Lage ist nicht die schönste, dafür gibt es aber einen schön gestalteten Außenbereich mit vielen Sitzmöglichkeiten.\nDer Verkäufer war auch sehr nett.\n\nFür Softeis Fans lohnt es sich auf jeden Fall!', '2025-06-25 13:08:18', NULL, 0),
(260, 264, 52, NULL, NULL, NULL, NULL, 'Sehr zentral gelegen und schön bunt eingerichtet, aber leider nicht so freundliches Personal \n\n+ Punkt es gibt auch Eisrollen', '2025-06-25 19:06:24', NULL, 0),
(261, 237, 52, NULL, NULL, NULL, NULL, 'Viele Sorten, große Kugeln und freundliche Mitarbeiter\n\nMan kann sich gut hinsetzen und das Eis genießen', '2025-06-27 10:57:03', NULL, 0),
(263, 272, 53, NULL, NULL, NULL, 20, 'Gute Lage und große Eisportionen. Geschmacklich gut mit Verbesserungspotential', '2025-06-29 21:20:38', NULL, 0),
(264, 273, 4, NULL, NULL, NULL, 12, 'Berries ist Teil von Parkers Pizza. Es gibt eine große Auswahl an Waffeln, Milchshake, Bubbletea und und und. \nEs gibt aber auch ganz normales Kugeleis im Becher oder Waffel.', '2025-06-29 21:22:42', NULL, 0),
(265, 275, 53, NULL, NULL, NULL, 30, 'Tolle Eisdiele mit original italienischen Eis. Die 2,2€ ist jede Kugel wert. Tolle Sorten und Größen ', '2025-06-30 18:28:15', NULL, 0),
(266, 276, 53, NULL, NULL, NULL, 20, 'Schöne kleine, ruhig gelegen Eisdiele am Hafen. Leider war das Eis wahrscheinlich schon mal ein wenig aufgetaut ', '2025-07-01 09:53:03', NULL, 0),
(267, 279, 1, NULL, NULL, NULL, 24, 'Ich könnte vor der Bestellung verschiedenste Eissorten ausprobieren.\nDer Verkäufer war sehr zuvorkommend und freundlich und hat es sehr gut mit den Portionen gemeint 🤤😁\n\nSpäter am Tag habe ich gesehen, dass das Hotel ihr Eis von der nahe gelegenen Eisdiele \'L\'atelier d\'écrin glacé\' bezieht.', '2025-07-02 13:55:32', NULL, 0),
(268, 280, 53, NULL, NULL, NULL, 20, 'Kleines Café mit tollem Eis. Kann fast übersehen werden.\nDer Bauernmarkt nebenan ist auch zu empfehlen', '2025-07-02 19:15:21', NULL, 0),
(269, 281, 53, NULL, NULL, NULL, 32, 'Absolut geniale Eisdiele Mut jeder Menge ungewöhnlicher Sorten und tollem Blick auf die Altstadt von Rovinj', '2025-07-03 08:20:53', NULL, 0),
(270, 155, 1, NULL, NULL, NULL, 34, 'Hier gibt es eine große Auswahl an leckeren Eissorten. Davon rund ein Drittel Sorbet-Eis und der Rest Milch-Eis.\nDirekt am See / Strand gelegen.', '2025-07-04 18:03:15', NULL, 0),
(272, 288, 40, NULL, NULL, NULL, NULL, 'Gute Lage am Strand, ', '2025-07-05 12:16:34', NULL, 0),
(273, 16, 2, NULL, NULL, NULL, 16, 'Sehr zentrale Lage im Roten Turm, ist auf jeden Fall einen Besuch und ein Eis wert!', '2025-07-05 13:44:34', NULL, 0),
(274, 8, 31, NULL, NULL, NULL, 17, 'Schönes Cafe mit leckeren Eis, schöner Außenbereich mit mehreren Sitz Möglichkeiten und es gibt noch anderen Aktivitäten (wie mini Golf) ', '2025-07-05 16:22:27', NULL, 0),
(275, 294, 53, NULL, NULL, NULL, 12, 'Kleines aber feines Café in einer ganz tollen kleinen Altstadt', '2025-07-05 19:02:05', NULL, 0),
(276, 178, 52, NULL, NULL, NULL, NULL, 'Es gibt hier sehr nette Mitarbeiter, die Eisdiele ist gut mit dem Fahrrad, Auto und auch zu Fuß erreichbar. Man kann das Eis sowohl auch die Eisbecher auch mitnehmen.', '2025-07-06 14:33:00', NULL, 0),
(278, 288, 78, NULL, NULL, NULL, 24, '', '2025-07-06 15:18:59', NULL, 0),
(279, 297, 1, NULL, NULL, NULL, 32, 'Etwas versteckt, sehr liebenswerter netter Betreiber. Große Auswahl an Milcheis, Sorbets und Softeis.\nAnscheinend ein kleiner Geheimtipp gegenüber den Eisdielen welche direkt an der Strandpromenade gelegen sind.', '2025-07-06 16:45:52', NULL, 0),
(280, 298, 53, NULL, NULL, NULL, 30, 'Mega Eisdiele, alles vom Feinsten. Die Entscheidung fällt schwer', '2025-07-06 21:03:58', NULL, 0),
(281, 300, 53, NULL, NULL, NULL, 32, 'Viele Sorten, guter Geschmack, gibt aber bessere', '2025-07-06 21:12:12', NULL, 0),
(282, 302, 1, NULL, NULL, NULL, NULL, 'Hier gibt es hausgemachte Kekse und Eis und die Kombination aus beidem.\nZum Beispiel einen Eisbecher mit 2 Kugeln Eis, einem Keks und einen Toppings für 7,50€', '2025-07-07 20:35:32', NULL, 0),
(283, 303, 62, NULL, NULL, NULL, 30, 'Es gibt eine grosse Auswahl an eissorten', '2025-07-08 12:30:51', NULL, 0),
(284, 305, 81, NULL, NULL, NULL, 10, 'Tolle Lage. Direkt am Jagst-Radweg.', '2025-07-08 19:57:57', NULL, 0),
(286, 306, 53, NULL, NULL, NULL, 12, 'Kleine Eisverkauf am Lim Fjord. Zugekauftes Eis aber dafür recht gut.', '2025-07-08 20:11:40', NULL, 0),
(287, 307, 8, NULL, NULL, NULL, 10, 'Teuer  \nGeschmack i.O.  - wir erhielten eine Warnung vor dem Minze-Eis …tastes like tooth paste', '2025-07-08 20:35:52', NULL, 0),
(288, 316, 52, NULL, NULL, NULL, NULL, 'Meiner Meinung nach das Beste Eis in Glauchau, das Eis schmeckt nicht so künstlich es gibt große Eisbecher und man kann sich auch gut draußen hinsetzen.\nAllerdings sind die Eisbecher mit 8,50€ relativ teuer.', '2025-07-10 15:02:14', NULL, 0),
(289, 318, 48, NULL, NULL, NULL, 8, 'Als wir da waren, war die Auswahl nicht ganz so groß. Aber die Lage ist neben dem Parlament natürlich einwandfrei. ', '2025-07-10 17:03:08', NULL, 0),
(290, 319, 48, NULL, NULL, NULL, 10, 'Es war eher ein Imbiss, mit Brötchen und warmen Snacks. Der Besitzer hat aber auch eine kleine Eistruhe gehabt. Mit sehr leckeren und auch besonderen Sorten. Er war sehr nett, auch wenn er kein Englisch konnte ', '2025-07-10 17:17:34', NULL, 0),
(291, 320, 48, NULL, NULL, NULL, 20, 'Richtig ausgefallene Sorten, die ich so noch nie gesehen habe. Richtig cremig und super präsentiert. Ich glaube, der Eisstand des Restaurants hat aber nur im Sommer auf. Wenn man mit seinem Eis 1 min läuft (wenn es so lange hält) kann man sich an die Donau setzten und direkt auf das Parlament schauen.', '2025-07-10 17:30:34', NULL, 0),
(292, 321, 53, NULL, NULL, NULL, 18, 'Tolle Eisdiele in Fazana mit dem geschmacklich bestem Eis', '2025-07-10 19:31:16', NULL, 0),
(293, 325, 40, NULL, NULL, NULL, 2, 'Softeis', '2025-07-11 15:40:21', NULL, 0),
(294, 326, 40, NULL, NULL, NULL, NULL, 'Das beste Eis in Zürich!', '2025-07-11 15:43:47', NULL, 0),
(295, 322, 1, NULL, NULL, NULL, 24, 'Hier gibt es keine klassischen Kugeln als Portion, sondern man wählt eine Becher bzw. Waffelgröße und kann dann je nach Größe verschiedene Anzahl an Geschmacksrichtungen wählen.\nKleine Waffel / Becher: 1-2 Sorten\nMittlere Waffel / Becher: 2-3 Sorten\nGroße Waffel / Becher: 3-4 Sorten\n\nDie Eis werden dann mit einem Spachtel in der Waffel oder dem Becher platziert.\n\nEs gibt eine große Auswahl an Sorten, draußen sowie drinne einige schöne Sitzmöglichkeiten.', '2025-07-11 19:51:24', NULL, 0),
(296, 324, 1, NULL, NULL, NULL, 18, 'Eigentlich ein Wein und Souvenir Shop, gibt es hier auch einige Sorten Eis zum Kauf.\n\nDie Preisgestaltung ist etwas unlogisch. Dafür ist die erste Kugel für französische Verhältnisse Recht günstig.\nDie zweite Kugel ist noch günstiger. Aber wenn man eine 3. Kugel dazu bestellt kostet diese 3. Kugel wieder mehr als die zweite.', '2025-07-11 19:53:39', NULL, 0),
(297, 331, 1, NULL, NULL, NULL, 6, 'Kleiner Imbiss vor dem Château Chenonceau, der neben belegten Brötchen auch ein paar Sorten Eis anbietet. Allerdings zu stattlichen Preisen 😅', '2025-07-12 10:54:45', NULL, 0),
(298, 337, 53, NULL, NULL, NULL, 18, 'Eiskugeln in guter Größe, Geschmack gut aber etwas süß', '2025-07-14 09:26:26', NULL, 0),
(299, 351, 1, NULL, NULL, NULL, 38, 'Direkt an der Strandpromenade gelegen gibt es hier sehr viele Sorten Eis zur Auswahl.\nDer Preis ist mit 3,90€ pro Kugel ziemlich teuer, vor allem da die Kugeln nicht sonderlich groß sind.', '2025-07-17 21:16:45', NULL, 0),
(300, 362, 1, NULL, NULL, NULL, 15, 'Hier gibt es neben belgischen Waffeln auch eine beachtliche Auswahl an Eis für einen günstigen Preis (für Maastricht).\n', '2025-07-19 11:36:42', NULL, 0),
(301, 363, 45, NULL, NULL, NULL, 17, '', '2025-07-19 11:48:59', NULL, 0),
(302, 202, 62, NULL, NULL, NULL, NULL, 'Standard Soft-Eis: Schoko-Vanille,\nGeschmack gut, Waffel geht auch', '2025-07-20 11:52:51', NULL, 0),
(303, 178, 31, NULL, NULL, NULL, 14, 'Schöne Eisdiele mit Terrasse, Standart Eissorten + paar Ausgefallene Sorten, verschiedene Eisbecher, Cafe usw. ', '2025-07-21 13:27:22', NULL, 0),
(304, 273, 1, NULL, NULL, NULL, 14, 'Bei der Pizzeria Parker gibt es auch eine gute Auswahl ausgefallener Eissorten. In der Bubblewaffel oder auch im Becher oder einer normalen Waffel.\r\n\r\nDie Pizzen sind auch sehr zu empfehlen.', '2025-07-24 16:48:43', NULL, 0),
(306, 378, 8, NULL, NULL, NULL, 36, 'Mega lecker \nMega Auswahl\nAmerika-teuer', '2025-07-24 21:46:20', NULL, 0),
(307, 380, 1, NULL, NULL, NULL, 15, 'Direkt in der Nähe der Burg und der Talsperre Kriebstein gelegen, befindet sich das Garten / Eiscafé.\nHier gibt es Kaffee, Kuchen, Eisbecher.', '2025-07-25 12:37:16', NULL, 0),
(308, 381, 22, NULL, NULL, NULL, 14, 'Kleine Eisdiele mit sehr ausgefallenen Sorten. Die Bedienung ist nett und man bekommt immer eine kleine Probierkugel oben drauf in der Sorte, dieman möchte.', '2025-07-25 20:21:47', NULL, 0),
(309, 382, 40, NULL, NULL, NULL, 6, 'Täglich frisch gemacht wechselnde 6 Eissorten\n\nhttps://www.gaultmillau.ch/zuri-isst/eisvogel-das-beste-glace-zurich\n', '2025-07-26 16:40:22', NULL, 0),
(310, 383, 4, NULL, NULL, NULL, 10, 'Es gibt viele bekannte Sorten, aber auch nette Sommerkombination!\nKleine Auswahl an Sorbet Eis.', '2025-07-26 18:20:12', NULL, 0),
(311, 113, 1, NULL, NULL, NULL, 12, 'Das Eiscafé liegt direkt am Bahnhof und hat einen großen Innen wie auch Außenbereich, sowie ein kleines Fenster für den Straßenverkauf von Eis.\n\nPositiv zu erwähnen ist dass Kartenzahlung möglich ist.', '2025-07-27 09:44:00', NULL, 0),
(312, 111, 1, NULL, NULL, NULL, 20, 'Wunderschön idyllisch gelegen gibt es bei Klett jeden Sonntag zwischen 13 und 18 Uhr Eis und andere Verpflegung im Gartenhäuschen zu kaufen.\r\n\r\nEs gibt viele gemütliche Sitzgelegenheiten mitten im Grünen. Die Betreiberin war super freundlich und die Preise sind auch top.\r\n\r\nEs gibt eine gute Auswahl ausgefallener Sorten, die insgesamt alle sehr natürlich und kein bisschen künstlich oder zu süß schmecken.', '2025-07-27 12:29:59', NULL, 0),
(313, 386, 98, NULL, NULL, NULL, 10, 'Schöne Eisdiele. Toll gelegen. Immer viele Familien davor die Eis schlecken. Ein toller Ort für das Viertel. Eiskugeln könnte größer sein. ', '2025-07-27 14:17:42', NULL, 0),
(314, 290, 40, NULL, NULL, NULL, NULL, 'Schöne Eisdiele im Quartier ', '2025-07-27 15:54:22', NULL, 0),
(315, 387, 2, NULL, NULL, NULL, 12, 'Schöne Lage direkt am Gardasee, viele Sitzmöglichkeiten. Eis schmeckt sehr natürlich fruchtig ', '2025-07-28 13:01:51', NULL, 0),
(316, 389, 2, NULL, NULL, NULL, 26, 'Schöne Eisdiele to go, aber recht teuer. Sonst viel Auswahl ', '2025-07-29 12:10:33', NULL, 0),
(317, 392, 2, NULL, NULL, NULL, 30, 'Sehr nette Eisdiele in der wunderschönen Stadt Malcesine. Wenn du mal hier bist, gerne hier anhalten für ein Eis.  Italienisch lecker mit schönem Außenbereich', '2025-08-01 12:45:28', NULL, 0),
(318, 396, 63, NULL, NULL, NULL, 32, '', '2025-08-01 18:49:51', NULL, 0),
(319, 393, 8, NULL, NULL, NULL, 6, '', '2025-08-01 20:43:35', NULL, 0),
(320, 314, 1, NULL, NULL, NULL, 10, 'Ein sehr guter Handwerksbäcker mit großer Auswahl an Kuchen, Teilchen, Brötchen, Brot und eben auch einige Eis-Sorten.\n\nDie Eissorten die ich probierte waren sehr lecker und der Service super freundlich 👍🏼☺️\n\nSchön dass es noch solche tollen Bäcker gibt.', '2025-08-02 10:00:07', NULL, 0),
(321, 397, 2, NULL, NULL, NULL, 28, 'Schöne Auswahl von fruchtig bis schokoladig. Sehr tolle Lage in einer schönen italienischen Stadt', '2025-08-02 12:14:43', NULL, 0),
(322, 400, 8, NULL, NULL, NULL, 24, '', '2025-08-02 13:58:25', NULL, 0),
(324, 401, 2, NULL, NULL, NULL, 20, 'Schöne Lage am Hafen, viele Sitzmöglichkeiten. Das Eis ist etwas teuer aber ganz lecker. Kann man mal machen, wenn man Lust hat', '2025-08-03 12:10:43', NULL, 0),
(325, 402, 2, NULL, NULL, NULL, 12, 'Nach einer leckeren Mittagspause mit Spaghetti Cabonara musste trotzdem noch ein Eis her. Auch wenn es eigentlich gar nicht mehr reingepasst hat - deshalb ohne Waffel. Leider war das Eis zu schaumig, weshalb es nicht ganz so lecker war. Rein geschmacklich sonst ganz gut. Es gab gegenüber auch noch eine andere Eisdiele, da kostet das Eis aber 2,50€! 🤔😂', '2025-08-04 12:46:05', NULL, 0),
(326, 404, 48, NULL, NULL, NULL, NULL, 'Die Sortenvielfalt hängt tatsächlich von der Wetterprognose ab, wenn nicht so gutes Wetter gemeldet ist wird weniger produziert sagte mir der Verkäufer. Trotzdem eine riesige Auswahl und auch besondere Sorten. Die Kugel könnte ein kleine bisschen größer sein, aber für 1,80€ kann man sich in Berlin absolut nicht beschweren. Premium Eis kann bis zu 2,50€ kosten. Außerdem gibt es noch Milchshakes und viele Kaffeeprodukte und auch Eisbecher. Im Winter gibt es hier nur eine winzige Auswahl an Eis, aber dafür gebrannte Mandeln und kandierte Äpfel 😋\r\nDie Lage an einer Kreuzung von zwei Hauptstraßen ist nicht die allerbeste, aber ein Eis geht immer :) ', '2025-08-05 08:00:11', NULL, 0),
(331, 71, 109, NULL, NULL, NULL, 16, 'Schöne Lage am Schillerplatz. Es handelt sich um einen Straßenverkauf, man kann mit dem Eis aber gut neben dem Spielplatz des Schillergartens platznehmen.', '2025-08-05 14:15:22', NULL, 0),
(333, 405, 109, NULL, NULL, NULL, 4, 'Es handelt sich um einen Imbiss mit klassischen Speisen, der daneben auch Eis von IceGuerilla (eine regionale Eismanufaktur) anbietet. Schöne Lage am See. Leider gab es kein reines Fruchteis.', '2025-08-05 14:35:12', NULL, 0),
(334, 406, 81, NULL, NULL, NULL, 7, 'Kleiner Eiswagen am Radweg\n', '2025-08-06 13:01:03', NULL, 0),
(336, 57, 1, NULL, NULL, NULL, 1, 'Hier gibt es jeden Tag ein anderes Softeis. Dazu kann man verschiedene Soßen und Toppings kombinieren.\nAußerdem kann man auch andere Waffeln für einen Aufpreis bekommen.', '2025-08-06 14:41:54', NULL, 0),
(337, 39, 52, NULL, NULL, NULL, NULL, 'Ausgefallene Sorten und nettes Personal ', '2025-08-07 12:56:17', NULL, 0),
(339, 356, 53, NULL, NULL, NULL, 4, 'Toller Außenbereich und leckeres Softeis in 3 verschiedenen Größen. Empfehlenswert!', '2025-08-07 17:59:39', NULL, 0),
(340, 271, 31, NULL, NULL, NULL, 2, 'Sehr schöner Laden, mit extrem guten Softeis. \nTäglich neue Sorten Softeis, außerdem gibt es noch sämtliche andere Biowaren. ', '2025-08-08 08:46:46', NULL, 0),
(341, 39, 31, NULL, NULL, NULL, 20, 'Schöne Eisdiele mit ausgefallenen Sorten, zum drin und draußen Sitzen und vielen Angeboten. ', '2025-08-08 08:54:07', NULL, 0),
(342, 407, 40, NULL, NULL, NULL, NULL, 'Nette Eisdiele am Dorfplatz ', '2025-08-08 17:21:47', NULL, 0),
(343, 102, 4, NULL, NULL, NULL, 10, 'Klassische Standardsorten. Achtung im Cafe-Bereich wird eine Servicepauschale von 45% erhoben!\nEs gibt neben Eis auch Kuchen und Bockwurst 😄', '2025-08-09 12:49:00', NULL, 0),
(344, 34, 102, NULL, NULL, NULL, NULL, 'Meiner Meinung nach, die beste Eisdiele der Stadt. Sitzplätze direkt am Geschehen, freundliche Bedienung und richtig leckeres, selbstgemachtes Eis mit Liebe. Außerdem auch Waffeln und Sorten für Veganer:innen oder Personen mit Laktoseintoleranz.', '2025-08-09 16:45:55', NULL, 0),
(345, 26, 52, NULL, NULL, NULL, NULL, '', '2025-08-10 06:13:57', NULL, 0),
(346, 273, 2, NULL, NULL, NULL, 13, 'Hier gibt\'s viele Leckereien zum Vesper ;) Eis ist okay, so eine bubblewaffel bestimmt sehr geil', '2025-08-10 11:40:30', NULL, 0),
(347, 158, 1, NULL, NULL, NULL, 12, 'Hier handelt es sich um einen kleinen Container / Eisverkaufsstand an der Straße.\nEs gibt eine kleine Bank für 2 Personen als Sitzmöglichkeit, das war\'s.\nDie Lage ist so mäßig schön und die beiden Betreiber auch nur so mäßig freundlich.', '2025-08-10 16:03:23', NULL, 0),
(348, 409, 48, NULL, NULL, NULL, 28, 'Nette Mitarbeiter, und eine große Auswahl. Zwar keine Sitzplätze aber das ist nicht schlimm. -nur Kartenzahlung möglich ', '2025-08-10 16:31:00', NULL, 0),
(349, 410, 53, NULL, NULL, NULL, 6, 'Tolles Softeis und leckere Waffeln als Stärkung vor dem Krupka Climb', '2025-08-11 09:34:11', NULL, 0),
(350, 411, 1, NULL, NULL, NULL, 10, 'Ein süßer kleiner Straßenverkauf zum Fenster heraus in der Innenstadt von Altenburg.\nHier gibt es täglich wechselndes Softeis und dazu viele Sorten aus dem Froster zum Mitnehmen.', '2025-08-12 15:48:00', NULL, 0),
(351, 408, 53, NULL, NULL, NULL, 10, 'Klein aber fein. Neben den Backwaren, teilweise auch sehr lokal ala Karl-Marx Kuchen noch 10 Eissorten. Hier kann man mal schön Pause machen', '2025-08-13 14:23:03', NULL, 0),
(352, 239, 2, NULL, NULL, NULL, 7, 'Eine sehr schöne Location mit gemütlicher Ambiente. Gibt auch viele andere Leckereien, aber das Eisangebot ist leider recht klein', '2025-08-15 13:07:43', NULL, 0),
(353, 84, 1, NULL, NULL, NULL, 21, '', '2025-08-17 20:24:28', NULL, 0),
(354, 418, 52, NULL, NULL, NULL, NULL, 'sehr schöner und großer außenbereich man kann hier direkt ein Kanu ausleihen ', '2025-08-18 13:25:27', NULL, 0),
(355, 178, 1, NULL, NULL, NULL, 14, 'Recht große Eisdiele mit vielen Sitzmöglichkeiten im Inneren und einer Terrasse.', '2025-08-18 14:26:51', NULL, 0),
(357, 77, 1, NULL, NULL, NULL, 1, 'Hier gibt es nur Vanilleeis.\nUnd verschiedene Eisbecher damit, also mit Erdbeeren oder Sause.', '2025-08-20 14:11:10', NULL, 0),
(358, 50, 1, NULL, NULL, NULL, 18, '', '2025-08-20 15:04:49', NULL, 0),
(359, 93, 1, NULL, NULL, NULL, 22, 'Schöne Lage mitten in der Altstadt von Döbeln mit großem Außensitzbereich.', '2025-08-20 15:51:02', NULL, 0),
(360, 420, 2, NULL, NULL, NULL, 5, 'Sehr leckere und günstige Gaststätte, es gibt aber auch ein paar wenige Eissorten für einen günstigen Preis, wobei der Geschmack aber durchschnittlich ist', '2025-08-23 18:39:40', NULL, 0),
(361, 179, 1, NULL, NULL, NULL, 16, 'Unscheinbar gelegenes kleines liebevoll geführtes Café.\r\nEs gibt einige Sitzgelegenheiten außen wie auch Innen.\r\n', '2025-08-24 12:44:15', NULL, 0),
(362, 38, 1, NULL, NULL, NULL, 13, 'Direkt auf dem Marktplatz gelegen  viele Sitzplätze außen wie auch Innen.', '2025-08-25 13:59:50', NULL, 0),
(365, 422, 1, NULL, NULL, NULL, 10, 'Direkt am Waldbadneuwürschnitz gelegen gibt es einen kleinen Imbiss, wo es Kugeleis und auch eine Sorte Softeis gibt.', '2025-08-26 16:08:27', NULL, 0),
(366, 353, 1, NULL, NULL, NULL, 17, 'Das Schild Design, die Sorten und der Geschmack lässt darauf schließen, dass es hier das gleiche Eis gibt wie beim Eiscafé Elisenhof.\r\nWas aber tatsächlich eines meiner Lieblings-Eis ist 😋', '2025-08-27 15:13:24', NULL, 0),
(369, 423, 53, NULL, NULL, NULL, 16, 'Neu eröffnete Eisdiele der Podolski Kette. Schön eingerichtet und auch ein schöner Außenbereich auf der Klosterstraße. Hier fühlt man sich wohl.', '2025-08-27 18:39:09', NULL, 0),
(370, 88, 1, NULL, NULL, NULL, 2, 'Hier gibt\'s neben Kuchen, Kaffee und Brötchen auch Softeis. Es gibt Schoko, Vanille gemischt oder einzeln.', '2025-08-29 14:01:09', NULL, 0),
(371, 423, 1, NULL, NULL, NULL, 16, 'Hier sind die Eissorten in Rühr Maschinen gelagert, wo sie wirklich regelmäßig neu gerührt werden, was das Eis sehr cremig macht.\r\nAnsonsten mitten in der Innenstadt von Chemnitz gelegen mit vielen Sitzmöglichkeiten außen und netten Service.', '2025-08-29 16:17:39', NULL, 0),
(373, 433, 40, NULL, NULL, NULL, 12, 'Schöne Eisdiele mit kremigen Sorten in einer beliebten Gegend von Lissabon ', '2025-08-30 10:56:36', NULL, 0),
(375, 432, 1, NULL, NULL, NULL, 20, '', '2025-08-30 11:30:47', NULL, 0),
(376, 435, 1, NULL, NULL, NULL, 17, '', '2025-08-30 12:47:27', NULL, 0),
(378, 439, 53, NULL, NULL, NULL, 6, 'Kleine und feine Eisdiele ', '2025-08-31 18:39:39', NULL, 0);
INSERT INTO `bewertungen` (`id`, `eisdiele_id`, `nutzer_id`, `geschmack`, `kugelgroesse`, `waffel`, `auswahl`, `beschreibung`, `erstellt_am`, `zuletzt_bearbeitet_am`, `is_on_site`) VALUES
(380, 104, 1, NULL, NULL, NULL, 2, 'Unscheinbar in zweiter Reihe gelegen befindet sich das kleine, charmante Eis-Café. Es gibt zwei Sorten Softeis und verschiedene (Eis)Kaffe Kreationen.', '2025-09-01 13:16:44', NULL, 0),
(381, 127, 1, NULL, NULL, NULL, 18, 'Mitten in der Fußgängerzone gibt es hier am Eisfenster Softeis und viele Sorten Kugeleis zu kaufen. Direkt davor gibt es einige Sitzmöglichkeiten.', '2025-09-01 13:59:38', NULL, 0),
(383, 442, 2, NULL, NULL, NULL, 7, 'Falls du nach dem Einkauf Lust auf ein Eis hast, bekommst du direkt noch beim Bäcker vor Ort eins. Auch wenn es kein Highlight ist, schmeckt es nicht schlecht. Leider sind die Kugeln für den Preis recht klein ', '2025-09-01 19:23:00', NULL, 0),
(384, 10, 77, NULL, NULL, NULL, NULL, 'Sehr schöne Eisdiele. Achtung: ab September nur noch Selbstbedienung, ab Oktober geschlossen.', '2025-09-02 16:39:20', NULL, 0),
(385, 447, 40, NULL, NULL, NULL, 12, 'Gut gelegene Eisdiele mit gutem Eis und großzügigen Portionen ', '2025-09-02 22:08:07', NULL, 0),
(386, 452, 30, NULL, NULL, NULL, 16, 'Die Eisdiele befindet sich mitten im Zentrum von Weimar in einer kleinen, niedlichen Seitenstraße. In der Straße gibt es ebenfalls eine Crêperie und ein sehr gutes Café. Im Laden gibt es mehrere Sitzmöglichkeiten. Insgesamt bot die Eisdiele am Tag des Verzehrs 16 verschiedene Sorten an. Ich habe mich für 1,5 Kugeln entschieden. Diese besten aus den Sorten: Himbeer - Weiße Schokolade, Apfel - Stachelbeere und Mango - Kokos - Maracuja. Alle drei Sorten waren sehr lecker, hatten eine top Konsistenz und waren auch in ihrer Größe sehr angemessen. Weiterhin entschied ich mich für eine Waffel und gegen den Becher. Gegen einen Aufpreis von lediglich 1 € lohnte sich die Waffel vollends. Die Waffel war eine der besten Waffeln, die ich bislang zu mir genommen habe. Große Empfehlung mit einem sehr freundlichen Personal. ', '2025-09-03 13:58:29', NULL, 0),
(390, 458, 109, NULL, NULL, NULL, 1, 'Ein toller Bäcker mit Straßen-Eisverkauf (nur Softeis) und kleinem Café. Es gibt auch Toppings fürs Eis. ', '2025-09-05 18:51:09', NULL, 0),
(391, 459, 4, NULL, NULL, NULL, 18, 'Sehr viel Auswahl, sowohl Klassiker der Eisküche, als auch moderne Eisinterpretationen.', '2025-09-06 06:08:46', NULL, 0),
(392, 466, 8, NULL, NULL, NULL, 26, 'Super leckeres Eis \r\nEtwas teuer aber lohnenswert', '2025-09-07 12:00:15', NULL, 0),
(393, 445, 1, NULL, NULL, NULL, 32, '', '2025-09-07 19:42:02', NULL, 0),
(394, 454, 1, NULL, NULL, NULL, 30, 'Schöne Eisdiele mit großer Auswahl, netten Personal und großer Auswahl.\r\n', '2025-09-07 20:05:08', NULL, 0),
(396, 468, 1, NULL, NULL, NULL, 32, 'Mitten in der Innenstadt schön gelegen mit großen Außenbereich zum Sitzen.', '2025-09-08 14:31:45', NULL, 0),
(397, 473, 53, NULL, NULL, NULL, 16, 'Sehr schöne Lage direkt im Zentrum von Bad Goisern. Leider sehr sehr unfreundliche Bedienung!!!', '2025-09-09 20:32:35', NULL, 0),
(398, 474, 1, NULL, NULL, NULL, 12, 'Bäcker mit einer kleinen Auswahl an Kugeleis.', '2025-09-10 07:18:46', NULL, 0),
(399, 476, 1, NULL, NULL, NULL, 24, 'Sehr liebevolle Eisdiele mit netten Service und einer großen Eisauswahl in der Innenstadt von Passau.\r\nAb 10€ ist auch Kartenzahlung möglich.', '2025-09-10 16:04:58', NULL, 0),
(400, 477, 1, NULL, NULL, NULL, 1, '', '2025-09-11 12:11:25', NULL, 0),
(401, 478, 8, NULL, NULL, NULL, 20, 'Eisdiele mit der besten Lage - atemberaubend schöne Gegend', '2025-09-11 15:50:47', NULL, 0),
(403, 479, 1, NULL, NULL, NULL, 11, 'Nur Barzahlung (tschechische Kronen) werden akzeptiert 😅', '2025-09-12 12:20:26', NULL, 0),
(405, 480, 8, NULL, NULL, NULL, 10, '', '2025-09-12 13:32:48', NULL, 0),
(406, 481, 1, NULL, NULL, NULL, 2, 'Kleiner Kiosk mit vielen Kuchen, Torten und Snacks im Angebot.\r\nHier gibt es auch Softeis in 2 Größen.', '2025-09-12 16:08:58', NULL, 0),
(408, 87, 1, NULL, NULL, NULL, 15, 'Kleines Eis-Lokal im Erdgeschoss eines Wohnhauses.\r\nSehr nette Verkäuferin, alles etwas in die Jahre gekommen.\r\n\r\nHier gibt es einige Sorten Kugeleis und auch Softeis im Angebot.\r\n', '2025-09-19 06:56:36', NULL, 0),
(412, 9, 2, NULL, NULL, NULL, 2, 'Leckeres Softeis! Immer wieder einen Besuch wert :)', '2025-09-20 13:01:24', NULL, 0),
(413, 9, 119, NULL, NULL, NULL, 2, 'Die Location ist mittlerweile etwas in die Jahre gekommen,ist aber bei vielen Einheimischen sehr beliebt. Es gibt einen kleinen Außenbereich mit Sitzgelegenheiten. Da er direkt an der Straße liegt,aber eher nur für einen kurzen Besuch geeignet. Das Softeis war okay.', '2025-09-20 13:07:32', NULL, 0),
(414, 414, 1, NULL, NULL, NULL, 1, 'Kleiner aber feiner Eis-Imbiss in der Nähe zum Radweg und mit einigen Sitzmöglichkeiten außen.\r\nAußerdem gibt es direkt einen kleinen Spielplatz direkt vor der Eisdiele.\r\n\r\nHier gibt es nur Softeis, einige Eisbecher-Kreationen auf Softeis Basis, sowie Kaffee und andere Getränke.', '2025-09-20 15:21:17', NULL, 0),
(416, 486, 1, NULL, NULL, NULL, 4, 'Hier gibt es Schoko, Vanille, Erdbeer und Stracciatella Eis zur Auswahl.\r\nDraußen gibt es einen großen Garten mit vielen Sitzmöglichkeiten und ganz vielen Gartenzwergen. Hat etwas von Schrebergarten 😁', '2025-09-21 08:47:47', NULL, 0),
(417, 427, 1, NULL, NULL, NULL, 14, '', '2025-09-21 10:42:08', NULL, 0),
(418, 53, 1, NULL, NULL, NULL, 1, 'Hier gibt es nur eine Sorte Softeis, dazu Milchshake, Eiscafé etc.\r\nBeliebte Eisdiele bei Motorradfahrern.', '2025-09-21 13:08:45', NULL, 0),
(421, 17, 53, NULL, NULL, NULL, 20, 'Sehr leckeres Eis und trotz Besuch zu später Stunde sehr nette und freundliche Bedienung. Große Eisportion und direkt in der Innenstadt', '2025-09-25 06:57:41', NULL, 0),
(424, 122, 1, NULL, NULL, NULL, NULL, 'Ein kleines Eis-café im Wintergarten eines Wohnhauses.', '2025-09-29 12:28:42', NULL, 0),
(428, 102, 1, NULL, NULL, NULL, 10, 'Direkt auf dem Markt gelegen bietet die Bäckerei Dietrich auch Eis. \r\nGroße Portionen für 1,60€ die Kugel', '2025-09-30 16:30:30', NULL, 0),
(429, 34, 1, NULL, NULL, NULL, 23, 'Mitten auf dem Markt gelegen gibt es hier einige Sitzplätze im Innenbereich und auch einige direkt auf dem Marktplatz.', '2025-10-01 13:02:34', NULL, 0),
(432, 482, 1, NULL, NULL, NULL, 18, '', '2025-10-02 11:37:16', NULL, 0),
(434, 492, 1, NULL, NULL, NULL, NULL, 'Hier gibt es eine Eiskarte mit verschiedenen Eisbechern. Die Eisbecher sind wirklich sehr günstig, aber das Eis ist leider auch nicht qualitativ das Beste.', '2025-10-03 18:03:59', NULL, 0),
(435, 498, 139, NULL, NULL, NULL, NULL, 'Für uns das beste Eis in Rom! \r\n\r\nLeider gibt’s bei dieser tollen Eisdiele keine Sitzgelegenheiten', '2025-10-04 16:54:22', NULL, 0),
(436, 497, 139, NULL, NULL, NULL, NULL, '', '2025-10-04 16:54:56', NULL, 0),
(437, 493, 139, NULL, NULL, NULL, NULL, 'Wenige Sitzgelegenheiten sind vorhanden ', '2025-10-04 16:55:47', NULL, 0),
(438, 499, 1, NULL, NULL, NULL, 18, 'Direkt am Inselzoo Altenburg gelegen liegt das Eis Häuschen was zu einem italienischen Restaurant gehört.\r\n', '2025-10-05 08:42:48', NULL, 0),
(440, 502, 139, NULL, NULL, NULL, NULL, 'Lt. Google Roms bestes Eis - hat uns aber nicht wirklich überzeugt. Sehr voll, sehr hektisch…', '2025-10-05 12:40:18', NULL, 0),
(442, 503, 139, NULL, NULL, NULL, 20, 'Gutes Eis zu Flughafenpreisen', '2025-10-06 09:03:44', NULL, 0),
(449, 270, 119, NULL, NULL, NULL, NULL, '', '2025-10-06 09:28:49', NULL, 0),
(450, 355, 1, NULL, NULL, NULL, 34, 'Direkt im Hbf Hannover gelegen gibt es hier jede Menge verschiedener Eissorten, auch Eisbecher, Frozen Joghurt und Snacks sind im Angebot.', '2025-10-09 07:36:27', NULL, 0),
(451, 516, 1, NULL, NULL, NULL, 18, 'Direkt in Strandnähe gibt es hier lecker Eis.\r\nKartenzahlung ist ab 5€ möglich.', '2025-10-10 15:38:32', NULL, 0),
(452, 520, 53, NULL, NULL, NULL, 18, 'Mega toller Laden mit vielen Eis- Kaffee- und Teesorten und tolle leckere Pralinen', '2025-10-10 18:26:19', NULL, 0),
(453, 518, 1, NULL, NULL, NULL, 11, '', '2025-10-10 20:00:44', NULL, 0),
(454, 527, 53, NULL, NULL, NULL, 1, 'Kleiner 24/7 Lokal Automat mit allem was es a6f dem Bauernhof gibt und Softeis', '2025-10-11 18:57:45', NULL, 0),
(456, 519, 1, NULL, NULL, NULL, 13, 'Schöne Eisdiele direkt in der Innenstadt von Silves. Kartenzahlung ab 5€ möglich.', '2025-10-12 20:42:33', NULL, 0),
(457, 517, 1, NULL, NULL, NULL, 20, 'Hier gibt es in Strandnähe eine große Auswahl an ausgefallenen, besonderen Eissorten.', '2025-10-12 20:44:23', NULL, 0),
(458, 532, 1, NULL, NULL, NULL, 18, 'Direkt am Strand gibt es hier zur Abwechslung mal richtiges Eis und nicht nur fertig abgepacktes Stileis', '2025-10-13 17:32:00', NULL, 0),
(459, 533, 53, NULL, NULL, NULL, 16, 'Super Eisdiele mit hausgemachten Eis', '2025-10-13 20:12:53', NULL, 0),
(460, 534, 53, NULL, NULL, NULL, 18, 'Besonders das Spaghetti-Eis ist zu empfehlen ', '2025-10-13 20:26:46', NULL, 0),
(461, 523, 1, NULL, NULL, NULL, 20, 'Etwas unfreundliche Bedienung und das Eis war auch nur okay.\r\nGegenüber die Eisdiele hat mir mehr zugesagt (sowohl geschmacklich als auch vom Service)', '2025-10-14 10:51:43', NULL, 0),
(462, 536, 53, NULL, NULL, NULL, 16, 'Tolles Eiscafe aber leider ist das Personal etwas genervt und unfreundlich', '2025-10-14 18:58:16', NULL, 0),
(463, 537, 53, NULL, NULL, NULL, 20, 'Kurzer Zwischenstopp in Jena bei Eiscafé Janny. Absolut nicht enttäuscht worden. Das Eis war sehr sehr lecker und kann nur weiterempfohlen werden. Komme gern mal wieder', '2025-10-14 19:07:21', NULL, 0),
(464, 510, 1, NULL, NULL, NULL, 16, 'Die Milcheis sind laut Ausschreibung alle aus Bio-Milch hergestellt.\r\nDie Eisdiele befindet sich direkt im Leipziger Hauptbahnhof.', '2025-10-15 17:16:07', NULL, 0),
(467, 543, 144, NULL, NULL, NULL, NULL, 'Ich liebe diese Eisdiele! Das Eis ist einfach himmlisch – alles hausgemacht und immer wieder gibt es neue, spannende Sorten zu entdecken. Das Personal ist super freundlich und man fühlt sich direkt willkommen. Besonders schön finde ich, dass man sein Eis sowohl drinnen als auch draußen auf dem Marktplatz genießen kann – unter den großen Bäumen schmeckt’s gleich doppelt so gut. Für mich ganz klar eine der besten Eisdielen in der Region!', '2025-10-19 17:53:19', NULL, 0),
(468, 544, 53, NULL, NULL, NULL, 16, 'Tolle Eisdiele mit freundlichem Personal, ausgefallenen Sorten und Topping und leckeren Toppings.', '2025-10-19 20:11:28', NULL, 0),
(470, 13, 1, NULL, NULL, NULL, 4, 'Hier gibt es neben selbst gemachten Softeis auch leckere Kuchen und Torten zu sehr fairen Preisen 👍🏼', '2025-10-21 14:16:48', NULL, 0),
(472, 546, 53, NULL, NULL, NULL, 3, 'Der Laden hat etwas, eigentlich von allem etwas. Leider sind die Preise etwas unverschämt ', '2025-10-23 20:12:13', NULL, 0),
(473, 547, 1, NULL, NULL, NULL, 8, 'Im Bahnhofsgebäude befindet sich dieser Imbiss, der aber von der Qualität absolut überrascht.\r\nHier gibt es eine riesige Auswahl an ausgefallenen Gerichten, wie Pizza, Burger Flammkuchen, Bowls und alles auch als vegetarische oder vegane Option.\r\n\r\nJedes Gericht ist schon etwas besonderes, so gibt es zum Beispiel auch Laugenpizza mit (auf Wunsch veganem) Leberkäse und süßen Senf.\r\n\r\nAuch leckere Kuchen, Torten und Desserts gibt es im Angebot.\r\n\r\nAuf Nachfrage habe ich erfahren, dass sie alles selber machen, vom Teig über die Pattys bis hin zu dem Eis. 👌🏼\r\n\r\nDie Preise sind auch sehr gut!', '2025-10-25 18:57:55', NULL, 0),
(474, 552, 53, NULL, NULL, NULL, 1, 'Haben auch einen kleinen mobilen Waagen mit Ziegenprodukten uns dort gibt\'s es Ziegeneis', '2025-10-26 19:46:09', NULL, 0),
(477, 561, 1, NULL, NULL, NULL, 5, 'Hofladen wo es 24/7 Eis aus der Tiefkühltruhe mit Kasse des Vertrauens gibt. Die Portionen sind 120ml für 2€.', '2025-11-01 12:14:12', NULL, 0),
(479, 21, 53, NULL, NULL, NULL, 10, 'Tolle Eisdiele, Softeis, Kugeleis und tolle Eisbecher.', '2025-11-01 21:39:03', NULL, 0),
(480, 92, 53, NULL, NULL, NULL, 10, 'Tolle Eisdiele Mut ausgefallenen Sorten sowohl Kugeleis wie auch Softeis. Gemütlicher Außenbereich.\r\n\r\nNeu, 24/7 Eisautomat', '2025-11-01 21:49:51', NULL, 0),
(481, 564, 1, NULL, NULL, NULL, 6, 'Bei der Schokoladenbar gibt es auch eine kleine Auswahl an Eis. Man kann mit Karte zahlen und bekommt die Kugel auch in der Waffel zum Mitnehmen. Auf jeden Fall ein Preis Geheimtipp für die Chemnitzer Innenstadt.', '2025-11-03 10:48:10', NULL, 0),
(483, 545, 1, NULL, NULL, NULL, 11, 'Sehr große Räumlichkeiten mit vielen Sitzmöglichkeiten.\r\nAls ich dort war, waren sehr viele Rentner Gruppen und teilweise Strick-Gruppen dort.\r\n\r\nAlles insgesamt sehr nett und günstig.\r\nLeider keine Kartenzahlung möglich.', '2025-11-05 14:32:00', NULL, 0),
(486, 567, 53, NULL, NULL, NULL, 16, '', '2025-11-08 14:00:43', NULL, 0),
(487, 569, 53, NULL, NULL, NULL, 10, '', '2025-11-09 21:52:01', NULL, 0),
(490, 174, 53, NULL, NULL, NULL, 7, 'Sehr schönes kleines Café mit leckerm Eis und tollem Kuchen. Sehr empfehlenswert sind auch die Windbeute', '2025-11-12 13:08:09', NULL, 0),
(491, 293, 1, NULL, NULL, NULL, 7, 'Ein super Café mit ganz lieben, tollen, superfeundlichen Inhabern. Neben tollen Torten, Kuchen und Kaffee gibt es hier auch ein Eisfenster leckeres Kugel Eis.', '2025-11-13 13:05:56', '2026-03-11 14:12:54', 0),
(492, 570, 1, NULL, NULL, NULL, 13, 'Gute Bäckerei / Konditorei mit leckeren Kuchen und Torten.\r\nAufgrund von Personalmangel nur Selbstbedienung.\r\nEis gab es am 15.11. nicht mehr. Vermutlich wird das nur in den Sommermonaten angeboten.', '2025-11-15 11:47:28', NULL, 0),
(496, 571, 53, NULL, NULL, NULL, 24, 'Eisdiele in der Nähe der Frankfurter Messe mit sehr vielen Sorten. Personal sehr freundlich.', '2025-11-19 19:00:28', NULL, 0),
(497, 565, 1, NULL, NULL, NULL, 6, 'Nettes kleines Café, neben Kuchen, Sandwiches und Bowls gibt es auch eine kleine Eis-Auswahl.\r\nKatzenzahlung ist auch bereits ab einer Kugel möglich.', '2025-11-28 07:07:54', NULL, 0),
(498, 574, 53, NULL, NULL, NULL, 4, 'Tolles Restaurant mit Pizza und Pasta und 4 leckeren Eissorten', '2025-11-28 20:10:51', NULL, 0),
(502, 577, 1, NULL, NULL, NULL, 40, 'Hier gibt es wirklich eine riesige Auswahl an Eissorten. Leider auch für einen sehr gepfefferten Preis, selbst für Schweizer Verhältnisse.', '2026-01-02 07:19:54', NULL, 0),
(503, 578, 1, NULL, NULL, NULL, 18, 'Bei diesem kleinen Fensterverkauf gibt es 18 verschiedene Sorten Eis, Bubblewaffels und Kaffee. \r\nDer Verkäufer war sehr freundlich aber es hat auch alles sehr lange gedauert.', '2026-01-02 07:21:45', NULL, 0),
(504, 161, 1, NULL, NULL, NULL, 6, 'Direkt an See gelegen gibt\'s hier in einem Häuschen Eis, Kaffee und Drinks.', '2026-01-02 20:17:39', NULL, 0),
(505, 581, 99, NULL, NULL, NULL, NULL, '', '2026-01-07 17:51:23', NULL, 1),
(506, 585, 2, NULL, NULL, NULL, 10, 'Ein niedliches Cafè mitten im Herzen von St. Ulrich. Wir haben nur den Straßenverkehr genutzt, aber man kann sich genauso reinsten. Allerdings nur die Standardsorten.', '2026-01-29 16:05:05', NULL, 0),
(507, 586, 40, NULL, NULL, NULL, 12, 'Sortenanzahl variiert. Gibt viele zur Auswahl.\r\nTolle Lage direkt neben dem Buffet.', '2026-02-04 21:12:51', NULL, 1),
(508, 589, 31, NULL, NULL, NULL, 20, 'Über 20 Sorten Eis, viele verschiedene Eisbecher im Angebot. ', '2026-02-07 21:13:16', NULL, 0),
(509, 587, 148, NULL, NULL, NULL, 36, '36 Kugeln Streicheis.\r\n4 Sorten Softeis.\r\nWas ein Traum 😋\r\n', '2026-02-08 07:44:40', NULL, 0),
(510, 579, 1, NULL, NULL, NULL, 14, 'Schöne Lage direkt an Strand.', '2026-02-09 10:30:42', NULL, 1),
(511, 594, 1, NULL, NULL, NULL, 14, 'Im Einkaufszentrum in der Etage -2 gelegen gibt es hier neben Calzone, Sandwiches auch ein paar Sorten Eis.', '2026-02-09 12:39:41', NULL, 1),
(513, 597, 1, NULL, NULL, NULL, 12, 'Nicht weit vom Meer entfernt gibt\'s hier sehr leckeres Eis.\r\nFruchteis Sorten sucht man hier vergeblich, aber dafür gibt es viele schokoladige / karemellige / süße Milcheis \r\nDie Sorten die ich hatte, hatten wirklich alle riesige Schoko, Karamell Stückchen und waren dadurch sehr sahnig, mächtig, lecker.\r\nVerkäuferin war nett.', '2026-02-09 20:15:47', NULL, 0),
(515, 36, 53, NULL, NULL, NULL, 8, 'Sehr schönes Ambiente und eine schöne Sitzgelegenheit außen. Das Kuchenangebot lockt auch.', '2026-02-10 14:01:45', NULL, 1),
(516, 602, 48, NULL, NULL, NULL, NULL, 'Nette Mitarbeiter und auch ein kleiner Bereich zum Eisbecher essen. Kartenzahlung möglich, dass ist auch immer gut und eine große Auswahl an verschiedenen Sorten ', '2026-02-10 17:22:45', NULL, 0),
(517, 600, 1, NULL, NULL, NULL, 10, 'Kleines Café in einer Gasse, wo es wahnsinnig viele Restaurants und Cafés gibt.', '2026-02-10 20:31:40', NULL, 0),
(518, 603, 1, NULL, NULL, NULL, 30, 'Hier gibt es wirklich eine riesige Auswahl an besonderen Sorten, alle mit vielen Toppings.\r\n', '2026-02-11 13:30:32', NULL, 1),
(519, 608, 48, NULL, NULL, NULL, 15, 'Im Winter nicht ganz so viele Eissorten, aber trotzdem noch sehr viele und spezielle. Ist eher aber auch ein Waffel und Cheesecake Laden so wie „Wonder Waffel“ ', '2026-02-11 18:57:59', NULL, 0),
(520, 609, 53, NULL, NULL, NULL, 20, 'Absolut tolle Eisdiele, schon das 3. Mal hier und jedes Mal wieder ein besonderes Eis. Absolute Empfehlung ', '2026-02-12 11:01:51', NULL, 0),
(521, 611, 48, NULL, NULL, NULL, 1, 'Gibt zwar „nur“ Vanille Softeis, aber dafür mit 11 verschiedenen Toppings und 4-5 Soßen ', '2026-02-12 20:18:43', NULL, 0),
(522, 615, 1, NULL, NULL, NULL, 16, 'Ein kleines Eisfenster mitten in der Innenstadt und zum Aufgang zur Zitadelle', '2026-02-13 15:46:27', NULL, 1),
(523, 618, 48, NULL, NULL, NULL, 16, 'Ist glaube eine Café Kette, aber das Eis war trotzdem sehr lecker und für den Alexanderplatz auch ein angenehmer Preis ', '2026-02-15 13:49:43', NULL, 0),
(525, 628, 53, NULL, NULL, NULL, 20, 'Eisdiele und Fruchtsäfte und Smoothies im Palladium Einkaufszentrum', '2026-02-19 14:24:33', NULL, 1),
(526, 620, 53, NULL, NULL, NULL, 20, 'Für mich die beste Eisdiele von Prag. Tolle Sorten, guter Preis und spezielle Toppings!', '2026-02-19 20:45:39', NULL, 0),
(527, 626, 53, NULL, NULL, NULL, 5, 'Es gibt kein direktes Kugeleis sondern Baumstritzel mit Eis und Früchten. Dafür mega lecker.', '2026-02-19 20:47:08', NULL, 0),
(528, 621, 53, NULL, NULL, NULL, 18, 'Schöne Auswahl an Eissorten und eine gemütliche Eisdiele', '2026-02-19 20:50:10', NULL, 0),
(529, 627, 53, NULL, NULL, NULL, 16, 'Hervorragende Lage gleich bei der Karlsbrücke. Eis sieht lecker aus und es gibt small bis large und Softeis', '2026-02-19 20:53:10', NULL, 0),
(531, 629, 53, NULL, NULL, NULL, 12, 'Ganz spezielle Eissorten und Törtchen. Alles Mega. Es gab sogar schon eine Auszeichnung zum Gelato World Tour Winner 2017', '2026-02-19 21:04:36', NULL, 0),
(532, 633, 98, NULL, NULL, NULL, NULL, 'sehr nette Eisdiele mit eiskugeln/ Eisbechern / Waffeln / usw. Nett zum sitzen ', '2026-02-21 13:51:04', NULL, 0),
(533, 634, 151, NULL, NULL, NULL, 12, 'Ausgefallene Eissorten allerdings hatten die, die wir probiert haben nicht wirklich Geschmack gehabt :(. Im Schloss gibt es 2 Eisstände aber bei beiden gibt es die gleichen Sorten. ', '2026-02-22 09:39:38', NULL, 0),
(534, 635, 48, NULL, NULL, NULL, 12, 'Viele verschiedene Sorten. Auch welche die man nicht überall sieht. Der Preis ist bisschen happig, aber für die Qualität des Eises auch okay. Es gibt im Sommer auch Sorbet Sorten als Veganer Option.', '2026-02-22 15:59:33', NULL, 0),
(535, 165, 53, NULL, NULL, NULL, 30, 'Ich bin gerne und oft hier und sehr zufrieden. Doch heute war wieder mal so ein Tag, naja. 6 Leute vor mir und über 15 min gewartet. Das Bedientempo war heute echt unterirdisch. Schade', '2026-02-25 19:25:18', NULL, 0),
(536, 177, 1, NULL, NULL, NULL, 17, 'Schön gelegen mit vielen Außenplätzen und einigen Liegestühlen, da kann man entspannt in der Sonne sein Eis schleckern.\r\nDie Bedienung war super freundlich zu mir ☺️', '2026-02-26 13:39:34', NULL, 1),
(537, 636, 53, NULL, NULL, NULL, 7, 'Automat am Hofladen mit tollen Leckereien und 7 hausgemachten Eissorten im Becher', '2026-02-26 16:36:14', NULL, 0),
(540, 639, 1, NULL, NULL, NULL, 12, 'Schön über den Schloßteich gelegen ist das Miramar eine wunderschön gelegene Anlaufstelle für Snackereien in der Chemnitzer Innenstadt.\r\n\r\nMit 1,70€ die Kugel gibt es hier für Chemnitz noch sehr günstig Eis und die Portionen sind auch ganz üppig dafür.\r\n\r\nAuf Nachfrage erzählte mir der nette Verkäufer, dass sie ihr Eis noch nicht selbst herstellen würden, aber das wohl in Planung sei.', '2026-03-03 20:06:09', NULL, 0),
(541, 11, 19, NULL, NULL, NULL, 16, 'Eine schöne,kleine, fast etwas unscheinbare Eisdiele auf dem Altmarkt Hohenstein-Ernstthal mit Innen- und Außenbereich. Das Eis aus eigener Herstellung schmeckt sehr \r\nlecker! Das Eierliköreis ist für mich hier der Hit. Softeis gibt es hier auch. ', '2026-03-07 14:25:05', NULL, 0),
(545, 316, 8, NULL, NULL, NULL, NULL, 'Sieben Vegane Sorten (Sorbets) ', '2026-03-07 19:33:48', NULL, 0),
(546, 167, 167, NULL, NULL, NULL, 22, 'Geheimtipp, alle Mega freundlich und Familien betrieben.\r\n', '2026-03-07 21:34:50', NULL, 0),
(547, 448, 118, NULL, NULL, NULL, 20, 'Nettes Personal, leckeres Eis und regelmäßig wechselnde Sorten. Perfekte Lage in der Innenstadt – immer einen Besuch wert!', '2026-03-08 15:54:09', NULL, 0),
(550, 5, 53, NULL, NULL, NULL, 20, 'Ein Traum, abwechslungsreiche Sorten und guter Geschmack. Auch Großpackungen zum Mitnehmen. ', '2026-03-09 13:51:12', NULL, 1),
(551, 314, 53, NULL, NULL, NULL, 10, 'Mein absoluter Lieblingsbäcker im Erzgebirge. Egal ob Brot, Kuchen oder Stollen, einfach spitze. Der Eistest steht aber noch aus. Die Mitarbeiter sind super nett und ganz besonders die Kinder stehen bei ihnen im Vordergrund 👍🏼', '2026-03-09 19:27:05', NULL, 0),
(552, 116, 1, NULL, NULL, NULL, 22, 'Im Innenhof vom Rasthof gelegen gibt es hier einige Sorten Eis und später im Jahr wohl auch Softeis im Angebot.\r\nWie man sieht leider keine Kartenzahlung :(', '2026-03-10 15:08:07', '2026-03-10 20:47:51', 1),
(553, 273, 53, NULL, NULL, NULL, 14, 'Mit Bubblewaffel sind viele Eisbecher toll wenn man nicht so einen süßen wählt. Das Eis ist okay, also eher Bubblewaffelbecher als Eis', '2026-03-10 17:47:07', NULL, 0),
(554, 20, 53, NULL, NULL, NULL, 12, 'Kleine tolle Eisdiele mit super nettem Personal', '2026-03-10 17:48:26', NULL, 0),
(559, 32, 53, NULL, NULL, NULL, 18, 'Schönes kleines Café direkt am Schlossteich. Spaziergang einmal um den Teich und dann ab ins Cafe 🤣', '2026-03-11 11:07:55', NULL, 1);
