(517, 1, 104, '2025-09-01 15:17:20', 'Softeis', 4.0, 3.7, NULL, 4.7, '', NULL, 'Fahrrad', 1, NULL),
(518, 1, 127, '2025-09-01 15:58:35', 'Kugel', 4.9, 4.0, NULL, 4.2, 'Das Kokosmakronen Eis war ein absolutes Highlight und hat wirklich exakt wie Kokosmakronen geschmeckt und hatte zusätzlich zu den Makronenstückchen auch noch Schokostückchen 😍😋😋\r\nDas Multivitamineis war fruchtig erfrischend und deutlich besser schmeckend als der gleichnamige Saft 😁\r\nPortionsgröße war für 1,60€ ziemlich gut und die Waffel auch ordentlich 👍🏼', NULL, 'Fahrrad', 1, NULL),
(519, 96, 165, '2025-09-01 17:36:33', 'Kugel', 4.0, 3.0, NULL, 4.5, '', NULL, 'Fahrrad', 1, NULL),
(520, 118, 441, '2025-09-01 21:21:14', 'Kugel', 5.0, 5.0, NULL, 5.0, 'Bestes Mokka-Eis, super cremige Sorten und tolle Kugelgröße zu unschlagbaren Preis. \r\nKinder bekommen auf Wunsch ein paar Smarties on top! 🥰\r\n', NULL, 'Zu Fuß', 0, NULL),
(521, 2, 442, '2025-09-01 21:24:51', 'Kugel', 3.9, 4.0, NULL, 3.4, 'Die Kugel schmeckte sehr schokoladig, aber war auch kein Highlight unbedingt. Hier fehlt das gewisse Etwas. Die Größe ist leider auch sehr klein für 1,60 pro Kugel. Ich mag die Waffel, ist wie Softeis', NULL, 'Auto', 0, NULL),
(522, 40, 437, '2025-09-02 17:19:06', 'Kugel', 5.0, 5.0, NULL, 5.0, '', NULL, 'Zu Fuß', 1, NULL),
