(564, 53, 477, '2025-09-14 11:21:13', 'Softeis', 5.0, 4.1, NULL, 5.0, 'Volltreffer. Total leckeres Softeis zum guten Preis. Rundum zufrieden. ', NULL, 'Fahrrad', 0, NULL),
(565, 1, 5, '2025-09-14 16:30:06', 'Kugel', 3.2, 4.3, NULL, 4.2, 'Cuba Libra hat wirklich auf den ersten Bissen sehr interessant und lecker geschmeckt, mit gutem Rum und Cola Aroma.\r\nAllerdings war der Geschmack mir für eine Kugel fast zu viel und es waren auch einige Eiskristalle enthalten, was sich bei der Sorte vielleicht nicht ganz verhindern lässt, aber natürlich trotzdem das Gesamtbild trübt.\r\n\r\nWaffel und Größe der Kugel waren gut.', NULL, 'Zu Fuß', 1, NULL),
(566, 22, 5, '2025-09-14 16:30:27', 'Kugel', 4.2, NULL, NULL, 4.0, 'Geschmacklich war es sehr lecker, doch hätte es etwas größer sein und bisschen mehr nach Schokolade schmecken können. Ansonsten lohnt sich aber ein Besuch denn es gibt auch viele ungewöhnliche Sorten.', NULL, 'Zu Fuß', 1, NULL),
(567, 1, 112, '2025-09-15 17:20:58', 'Softeis', 4.4, NULL, NULL, 3.9, 'Als Topping gab es weiße Schokoladensoße (+0,50€) und Oreo-Crumble (+0,50€).\r\nDas Eis war insgesamt ganz gut, allerdings könnte es sahniger / cremiger sein.', NULL, 'Zu Fuß', 0, NULL),
(568, 137, 483, '2025-09-16 20:12:40', 'Kugel', 4.8, 3.6, NULL, 4.8, 'Sehr schmackhafte und große Kugeln zu einem günstigen Preis (1,40€). ', NULL, 'Zu Fuß', 0, NULL),
(569, 137, 484, '2025-09-16 20:33:41', 'Kugel', 4.8, NULL, NULL, 3.9, 'Sehr leckere Eissorten, genügend Sitzmöglichkeiten drinnen und draußen. ', NULL, 'Fahrrad', 0, NULL),
(571, 1, 145, '2025-09-17 17:04:15', 'Kugel', 4.8, 3.5, NULL, 4.9, 'Das Brezeleis ist wirklich eine Offenbarung 😍😍🤤🤤\r\nWer Salted Caramel mag, wird Brezel lieben 😍\r\nPistazieneis was auch sehr solide, dazu ist der Preis mit 1,20€ pro Kugel wirklich sehr gut.\r\nSchade dass die Waffel nicht so gut ist.', NULL, 'Fahrrad', 1, NULL),
(572, 137, 485, '2025-09-17 18:30:53', 'Kugel', 4.6, NULL, NULL, 3.5, 'Sehr große Auswahl an Eissorten, viele Sitzmöglichkeiten im Café und im Eisgarten.', NULL, 'Fahrrad', 0, NULL),
(573, 1, 87, '2025-09-18 14:20:55', 'Kugel', 2.6, 2.0, NULL, 3.2, 'Das Tiramisu Eis hat wirklich nicht gut geschmeckt.\r\nApfel-Birne-Kiwi hat schon etwas besser geschmeckt ... etwas wie Multivitamin, aber insgesamt auch kein Highlight.\r\nDie Kugeln waren zwar mit 1,40€ sehr günstig aber auch echt winzig.\r\n\r\nDie Waffel war zwar prinzipiell eine knusprige, hat aber total weich geschmeckt, als hätte sie Feuchtigkeit abbekommen.', NULL, 'Fahrrad', 1, NULL),
(574, 1, 2, '2025-09-18 16:12:03', 'Kugel', 4.2, 4.5, NULL, 4.1, 'Das Eis hatte einige Keksstückchen, war vernünftig groß aber hatte einen etwas bananigen Beigeschmack den ich nicht so mochte.\r\nDie Waffel war sehr knusprig.', NULL, 'Fahrrad', 1, NULL),
(575, 118, 450, '2025-09-18 19:25:04', 'Kugel', 5.0, NULL, NULL, 5.0, 'Leckeres Eis. 😍 Ausgesprochen guter Service! ', NULL, 'Auto', 0, NULL),
