(577, 4, 51, '2025-09-19 14:05:09', 'Eisbecher', 4.4, NULL, NULL, 4.1, 'Cookie ist sehr solide. Das Nougat Eis mit Nussstücke. Sehr zu empfehlen!', NULL, 'Zu Fuß', 0, NULL),
