(848, 53, 353, '2026-03-08 21:09:50', 'Kugel', 4.2, NULL, NULL, 3.8, '', NULL, 'Zu Fuß', 0, NULL),
(849, 53, 36, '2026-03-09 14:39:42', 'Kugel', 4.7, NULL, NULL, 4.0, '', NULL, 'Fahrrad', 1, NULL),
(850, 53, 5, '2026-03-09 14:53:40', 'Kugel', 5.0, NULL, NULL, 4.3, 'Super leckeres Eis mit Reiskörnern und dezentem Zimtgeschmack. Top.\r\nEins gegessen, Großpackung für Zuhause.', NULL, 'Fahrrad', 1, NULL),
(851, 10, 277, '2026-03-10 13:47:52', 'Eisbecher', 5.0, NULL, NULL, 5.0, 'Wir haben unsere Tochter zum Kindergeburtstag in die Tanzeria gebracht und die freie Zeit gleich gut genutzt. Die Eis Diele ist mit allem gut erreichbar, auch ist eine Straßenbahn gleich in der Nähe. Es gibt super Fahrradwege um die verschiedenen Seen. Der Laden hat über 70 verschiedene Eisbecher, die alle sehr moderate Preise haben. Ich habe einen Kaffee Becher inkl. Espresso und meine Frau ein Kaffee Spaghetti Eis. Beides unter 11€. Es gibt auch Bubble Waffel Eis, was wir das nächste Mal probieren. Ein Besuch ist der Laden wert!', NULL, 'Auto', 0, NULL),
(852, 86, 5, '2026-03-10 13:49:59', 'Kugel', 5.0, NULL, NULL, 4.3, 'Schmackhaftes Eis mit viele ausgefallenen Sorten ', NULL, 'Bus / Bahn', 0, NULL),
(853, 1, 11, '2026-03-10 15:21:56', 'Kugel', 4.8, 3.0, NULL, 4.4, 'Bei Sanddorn handelt es sich um ein Fruchteis und dennoch war die Kugel sehr sahnig und wahnsinnig lecker 😋😊\r\nBei nur einer Kugel gab es leider auch nur die leicht pappige Waffel. Da lohnt es sich in eine zweite Kugel zu investieren.', NULL, 'Fahrrad', 1, NULL),
(854, 1, 116, '2026-03-10 16:03:12', 'Kugel', 4.3, 1.5, NULL, 4.7, 'Das Eis hatte einige Keksstücke, war aber dafür geschmacklich nicht so gut wie man es vielleicht erwarten würde.\r\nDie Waffel war leider eine der pappigsten Kategorie 😬', NULL, 'Fahrrad', 1, NULL),
(855, 118, 449, '2026-03-10 16:29:02', 'Kugel', 4.0, NULL, NULL, 5.0, '', NULL, 'Fahrrad', 1, NULL),
(856, 1, 19, '2026-03-10 17:10:53', 'Softeis', 3.6, 2.0, NULL, 2.0, 'Zum Abschluss der Runde noch ein Softeis und meine dritte Challenge erfüllt 🍦🫡\r\n\r\nGeschmacklich ganz okay, aber auch sehr teuer.\r\nDie Lage ist natürlich sehr schön ☺️', NULL, 'Fahrrad', 1, NULL),
(857, 53, 273, '2026-03-10 17:23:15', 'Kugel', 4.0, NULL, NULL, 4.5, '', NULL, 'Fahrrad', 1, NULL),
(858, 53, 20, '2026-03-10 18:49:51', 'Kugel', 4.8, NULL, NULL, 5.0, 'Lecker Eis mit toller Vanillenote. Nicht zu süß und ein unschlagbarer Preis.', NULL, 'Fahrrad', 0, NULL),
(859, 53, 408, '2026-03-11 09:28:59', 'Kugel', 4.0, NULL, NULL, 4.0, '', NULL, 'Fahrrad', 1, NULL),
(860, 53, 32, '2026-03-11 12:14:55', 'Kugel', 4.5, 4.2, NULL, 3.2, 'Die Mittagspause wären der Pendelei mal für ein Eis genutzt. Schmeckt lecker mit großen Pistazienstücken aber für 2,20€ leider viel zu klein. Waffel schön knusprig ', NULL, 'Fahrrad', 1, NULL),
(861, 1, 293, '2026-03-11 14:41:15', 'Kugel', 5.0, 4.8, NULL, 5.0, 'Nach einem super netten Gespräch mit den Betreibern gab es für mich noch eine Kugel Eis 😍😋\r\nQuark Limette war wirklich sehr lecker, schön cremig und eine angenehm säuerlich, erfrischende Note von der Limette.\r\n\r\nDas besondere eine knusprige Waffel die sogar vegan ist. 😎👍🏼\r\n\r\nKarl mags süß ist eine Top Empfehlung! ☺️\r\n\r\nP.S. in ein paar Tagen werdet ihr mehr erfahren, was ich mit den Inhabern besprochen habe 😎', NULL, 'Fahrrad', 1, NULL),
(862, 156, 32, '2026-03-11 16:08:41', 'Kugel', 4.0, 4.0, NULL, 3.5, 'Eis und Waffel waren lecker.', NULL, 'Zu Fuß', 0, NULL),
(863, 31, 649, '2026-03-11 19:36:24', 'Kugel', 4.8, 1.4, NULL, 2.3, '', NULL, 'Auto', 1, 34),
(864, 52, 649, '2026-03-11 19:36:24', 'Kugel', 5.0, NULL, NULL, 3.7, '', NULL, 'Auto', 0, 34),
(865, 53, 5, '2026-03-11 21:28:00', 'Kugel', 4.5, NULL, NULL, 4.2, 'Immer wieder lecker das Amarena Kirsch. Viele Früchte drin. Jummi', NULL, 'Zu Fuß', 0, NULL),
(866, 31, 650, '2026-03-11 22:00:38', 'Kugel', 5.0, NULL, NULL, 3.2, '', NULL, 'Zu Fuß', 1, NULL);
