INSERT INTO `kommentare` (`id`, `nutzer_id`, `checkin_id`, `bewertung_id`, `kommentar`, `erstellt_am`, `route_id`, `user_registration_id`) VALUES
(1, 1, 186, NULL, 'Ohh interessant, Erdbeer-Vanille muss ich auch mal ausprobieren! 😋😍', '2025-06-13 05:38:17', NULL, NULL),
(2, 1, 185, NULL, 'Sieht echt sehr lecker aus! 😋 \nIst schon eine gute Eisdiele. Bei mir war der Verkäufer auch wahnsinnig freundlich.\nMit der Platzsituation hast du natürlich recht, gerade mit der Family wirds da eng mit Rädern.', '2025-06-13 05:39:49', NULL, NULL),
(3, 1, 182, NULL, 'Mit dem Cityroller ist natürlich auch mal was anderes :D', '2025-06-13 05:40:33', NULL, NULL),
(4, 1, 184, NULL, 'Sehr coole Radtour die du da zurück gelegt hast 🚴🏼‍♂️👍🏼\nUnd gleich zwei neue Eisdielen eingecheckt 🔥🫶🏼', '2025-06-13 05:42:36', NULL, NULL),
(5, 1, 187, NULL, 'Willkommen auf der Ice-App und vielen Dank für deinen ersten CheckIn 🤗\nWeißt du zufällig noch wie teuer eine Kugel Eis war?', '2025-06-13 05:56:36', NULL, NULL),
(6, 1, 180, NULL, 'Die Waffel sieht ja mal richtig lecker aus! 😍​', '2025-06-13 06:00:57', NULL, NULL),
(7, 1, 71, NULL, 'sieht echt Hammer aus! 🤩​ Mango ist natürlich auch ne geile Geschmacksrichtung für Softeis.\n\nAber die Waffel sieht mir doch recht pappig aus 😅', '2025-06-13 06:06:10', NULL, NULL),
(9, 13, 186, NULL, 'Richtiger Stammkunde bei der Eisdiele Dietz! Gefällt mir!', '2025-06-13 06:25:04', NULL, NULL),
(12, 1, 188, NULL, 'Da wurde sich schön ein Eis zum Geburtstag gegönnt 😍😋\nHerzlichen Glückwunsch zum Geburtstag und ich hoffe es hat geschmeckt 🥳😁', '2025-06-13 11:27:40', NULL, NULL),
(13, 1, 193, NULL, 'Sehr geil, das ist wirklich geschmacklich eine meiner absoluten Lieblingseisdielen! 😍\nich hab gelesen die haben auch einen Eis-Burger wo das Eis in einem Ufo-Burger-Brötchen eingebacken wird. 🧐\nDen will ich mal ausprobieren wenn ich das nächste Mal dort bin', '2025-06-15 18:17:10', NULL, NULL),
(14, 1, 190, NULL, 'Oha, das ist ja wirklich ein riiesiges Eis! 🤩', '2025-06-15 18:17:52', NULL, NULL),
(15, 23, 193, NULL, 'Oh, das muss ich mir mal anschauen. Die liegen ja direkt in der Umgebung, für mich ist\'s einfacher da mal vorbeizuschauen. ☺️', '2025-06-16 08:07:15', NULL, NULL),
(16, 1, 194, NULL, 'Oh zyprisches Eis 🤓😏\nDann schmecken lassen und einen schönen Urlaub! 😎', '2025-06-16 15:51:30', NULL, NULL),
(17, 47, 187, NULL, 'Ach hab ich wohl vergessen zu schreiben ;) 1,80€', '2025-06-17 16:13:17', NULL, NULL),
(18, 1, 198, NULL, 'Du genießt ja fleißig das Eis in Zypern! :)\nLeider gab es einen Bug, so dass es die eingecheckten Sorten nicht gespeichert hat.\nDen habe ich aber schon behoben, wenn du willst kannst du deinen Checkin ja nochmal bearbeiten und die Sorten nochmal eintragen.', '2025-06-17 17:36:42', NULL, NULL),
(19, 1, 195, NULL, 'Hey, schön dich bei der Eis-App begrüßen zu können! :)\nLeider gab es einen Bug, so dass es die eingecheckten Sorten nicht gespeichert hat.\nDen habe ich aber schon behoben, wenn du willst kannst du deinen Checkin ja nochmal bearbeiten und die Sorten nochmal eintragen.', '2025-06-17 17:37:21', NULL, NULL),
(20, 1, 199, NULL, 'Hey, leider gab es einen Bug, so dass es die eingecheckten Sorten nicht gespeichert hat.\nDen habe ich aber schon behoben, wenn du willst kannst du deinen Checkin ja nochmal bearbeiten und die Sorten nochmal eintragen. :)', '2025-06-17 17:37:53', NULL, NULL),
(21, 31, 194, NULL, 'Danke :)', '2025-06-17 20:10:01', NULL, NULL),
(22, 1, 205, NULL, 'Einen schönen Urlaub wünsche ich dir! 😊\nViel Spaß in der Heimat des Gelatos 🇮🇹🍨', '2025-06-18 17:15:30', NULL, NULL),
(23, 49, 205, NULL, 'Dankeschön 🍀🇮🇹', '2025-06-19 11:57:29', NULL, NULL),
(24, 1, 217, NULL, 'Herzlich Willkommen auf der Ice-App 🫶🏼🍦\nUnd weiterhin viele leckere Eis und noch einen schönen Urlaub! 😊', '2025-06-21 03:06:54', NULL, NULL),
(25, 1, 232, NULL, 'Pistazie und weiße Schokolade sind schon sehr geile Sorten 😋🤤\n\nWeißt du zufällig noch wie teuer eine Kugel Eis war? 😅', '2025-06-23 15:48:45', NULL, NULL),
(26, 1, 246, NULL, 'Eine wirklich sehr gute Eisdiele 👌🏼😋', '2025-06-25 14:36:25', NULL, NULL),
