(160, 1, 769, NULL, 'Ja nur ein kleines Topping quasi 😅\nMusste auch bei den 16 Grad schon schnell schlecken um es vom davonlaufen zu schützen 😂', '2026-02-10 17:12:50', NULL, NULL),
(161, 1, 771, NULL, 'Mit vollem Einsatz das zweite Eis des Tages und die erste Challenge abgeschlossen 💪🏼🤤🥳', '2026-02-10 21:04:25', NULL, NULL),
(162, 1, 778, NULL, 'Sehr geil, wie aktiv du bei der Eis-Olympiade bist 💪🏼😎', '2026-02-11 21:43:36', NULL, NULL),
(163, 48, 778, NULL, 'Wenn ich es schon nicht zu Olympia schaffe, dann wenigstens eine gute Platzierung bei der Eis-Olympiade holen. Und natürlich leckeres Eis essen 😋', '2026-02-11 21:48:01', NULL, NULL),
(164, 1, 778, NULL, 'That\'s the Spirit 💯\nUnd irgendwann wird Eis essen noch olympisch und dann treten wir im Zweier-Eisfutterschacht an 😁', '2026-02-11 21:53:30', NULL, NULL),
(165, 48, 778, NULL, 'Ob Eis essen, bei den Sommerspielen oder Winterspielen eingestuft wird? Würde beides Sinn machen? 🙈', '2026-02-11 22:04:34', NULL, NULL),
(166, 1, 778, NULL, 'Guuuute Frage 🤔\nVielleicht bei beiden Olympiaden. Im Winter die Eisbecher Spezialisten und im Sommer dank dir Kugel- und Softeis Schlecker 🧐', '2026-02-12 05:50:03', NULL, NULL),
(167, 1, 779, NULL, 'Das sieht ja echt geil aus 😍\nIst ja schon mehr ein Eisbecher 😁', '2026-02-12 11:28:56', NULL, NULL),
(168, 53, NULL, 518, 'Na da wäre auch das ein oder andere Eis für mich dabei 👍🏼 Schönen Urlaub', '2026-02-13 11:05:31', NULL, NULL),
(169, 48, 783, NULL, 'Und reichlich Sahne darfst du nicht vergessen 😅', '2026-02-13 22:05:51', NULL, NULL),
(170, 1, 783, NULL, 'Na wenn das Engelshaare von Erzengel Castello persönlich kommt muss es ja schmecken 😂😂', '2026-02-14 08:51:21', NULL, NULL),
(171, 22, 741, NULL, 'Nicht wie bei der Gelateria die Berna? 😋', '2026-02-15 11:40:11', NULL, NULL),
(172, 40, 741, NULL, 'Nein.. Arancio Rosso ist der eigentliche Stracciatella Favorit.', '2026-02-15 14:30:16', NULL, NULL),
(173, 1, 788, NULL, 'Geht ab bei dir 😁👍🏼\nSieht auf jeden Fall schmackofatz aus das Eis 😍\nJetzt musst du nur noch deine Begleitung überreden einzuchecken 😉', '2026-02-15 15:20:29', NULL, NULL),
(174, 48, 788, NULL, 'Eigentlich hab ich Selina unten eingetragen bei dem Feld, mit wem man da war 🙈 aber das stimmt, Selina muss auch mal ein Eis einchecken 😅', '2026-02-15 15:23:07', NULL, NULL),
(175, 1, 788, NULL, 'Ja da muss sie schon noch selbst in der App aktiv werden 😉😁', '2026-02-15 15:58:36', NULL, NULL),
(176, 48, 806, NULL, 'Ohhh nein, das tut mir voll leid, dass du so eine negative Eis experience hattest 🥺 Ich hoffe das nächste Eis wird dafür um so leckerer 😋', '2026-02-22 09:42:02', NULL, NULL),
(177, 1, 806, NULL, 'Das ist ja wirklich schade, da sieht das Eis so lecker aus und dann so eine Enttäuschung :( \nDer Frust ist verständlich!', '2026-02-22 13:18:45', NULL, NULL),
(178, 1, 807, NULL, 'Sehr schöner Erfahrungsbericht 🫶🏼\n4,20€ ist natürlich wirklich Hammer hart für Deutschland 😵‍💫\nAber bei Preis-Leistung von 5,0 scheint es das wert zu sein 😁', '2026-02-22 16:28:17', NULL, NULL),
(179, 51, 806, NULL, 'Das nächste Eis wird dafür umso besser :D', '2026-02-22 16:35:39', NULL, NULL),
(180, 51, 807, NULL, '#Wiederholungsbedarf', '2026-02-22 16:37:09', NULL, NULL),
(181, 48, 807, NULL, 'Ja, das Eis war wirklich Weltklasse. Da kann man schon mal 4,20€ bezahlen. Aber das stimmt, wenn man das in Relation setzt, dass man da eventuell doch alle zwei Wochen mal ein Eis essen will, dann passt das Preis Leistungs Verhältnis von 5,0 nicht mehr 🙈', '2026-02-22 16:38:47', NULL, NULL),
(182, 1, NULL, 535, 'Ich hatte auch mit dem Gedanken gespielt dort heute einen Halt zu machen, aber als ich die Schlange gesehen habe bin ich doch weiter gefahren 😅', '2026-02-25 19:34:23', NULL, NULL),
(183, 1, 815, NULL, 'Griechischer Baum klingt ja interessant 🤔😅\n\nEinen schönen Aufenthalt in Griechenland euch noch! 😊😎', '2026-02-27 16:48:34', NULL, NULL),
(184, 1, 819, NULL, 'Herzlich Willkommen auf der Ice-App 🫶🏼☺️\nBäckerei Bräunig ist auf jeden Fall eine gute Wahl! 😎\nAuf noch viele tolle Eis-Momente!', '2026-03-01 06:23:42', NULL, NULL),
(185, 1, 826, NULL, 'Ich sehe da hat jemand seine absolute Lieblingseisdiele gefunden! 😁\nSieht ja aber auch fantastisch aus! 😋', '2026-03-04 19:03:11', NULL, NULL),
(186, 1, 828, NULL, 'Lauf zur friedvollen Erdbeerkugel 👌🏼🤣', '2026-03-05 20:51:43', NULL, NULL),
(187, 1, NULL, NULL, 'Hey, herzlich Willkommen auf der Ice-App 🫶🏼 \nSchön dass du hier bist und viele tolle Eis-Momente dir!', '2026-03-06 10:49:27', NULL, 158),
(188, 118, 819, NULL, 'Die beste Wahl. Sowohl er als auch das Eis! <3', '2026-03-06 14:15:54', NULL, NULL),
(189, 1, NULL, NULL, 'Hey, herzlich Willkommen auf der Ice-App 🫶🏼 \nSchön dass du hier bist und viele tolle Eis-Momente dir!😋🍦🍨', '2026-03-06 16:44:31', NULL, 159),
(190, 1, 831, NULL, 'Herzlich Willkommen auf der Ice-App 🫶🏼\nSchön dass du dabei bist und auf viele weitere tolle Eis-Momente 🍦😋', '2026-03-06 19:19:19', NULL, NULL),
(191, 1, 832, NULL, 'Hey, cool dich auf der Ice-App begrüßen zu dürfen 🤗 und herzlichen Glückwunsch zum ersten Check-in 🎉🍦', '2026-03-07 06:55:30', NULL, NULL),
(192, 165, 832, NULL, 'Hey, vielen Dank! Ich war schonmal bei euch, aber irgendwie war mein Konto weg. Eis ist einfach immer lecker... 🫶😊🍦', '2026-03-07 07:02:47', NULL, NULL),
(193, 1, NULL, 541, 'Oh ich wusste bis eben gar nicht dass es dort auch Softeis gibt 🤔🍦\nMuss ich wohl demnächst mal wieder vorbei 😎', '2026-03-07 14:35:32', NULL, NULL),
(194, 1, 837, NULL, 'Hey, herzlichen Glückwunsch zum ersten Check-in 👌🏼\nJa das mit den Waffeln bei Marshners ist bisschen wie Lotterie spielen... 😅\nAber soll ja Leute geben, denen eine pappige Waffel lieber ist. Meins ist es auch nicht 😵‍💫', '2026-03-07 14:37:42', NULL, NULL),
(195, 19, NULL, 541, 'Ja, warte mal noch bisschen, zumindestens wenn du Softeis möchtest 😉\nHeute war die Softeismaschine noch aus. Aber mit steigenden Temperaturen in den nächsten Wochen kommt das bestimmt auch wieder hinzu.', '2026-03-07 15:42:26', NULL, NULL),
(196, 1, 839, NULL, 'Na das ist ja mal ein Premium Check-in 👌🏼😎\nMit gaaaanz viel Liebe 👩‍❤️‍💋‍👨\nUnd dann auch noch kurfürstlicher Eis Experte Sachsens geworden 🤣\nDie Bilder haben auf jeden Fall Potential bei der Fotochallenge ganz weit oben mit zu spielen 🏆📸', '2026-03-07 16:50:45', NULL, NULL),
(197, 8, 839, NULL, 'War ein toller 3-Generationen-Ausflug.  Zitat Alex: \nSo langsam sind die Tage gezählt dass man sagen kann: die Radtour mit den Kids ist entspannt', '2026-03-07 18:39:35', NULL, NULL),
(198, 1, 780, NULL, 'Hey du alter Eis-Schleck-Rakete! 🍦🚀\nDas Bild sieht super aus. \nWillst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁', '2026-03-08 05:49:32', NULL, NULL),
(199, 1, 171, NULL, 'Hey du alter Eis-Schleck-Rakete! 🍦🚀\nDas Bild sieht super aus. \nWillst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁\nDanach beginnt das Voting', '2026-03-08 05:50:49', NULL, NULL),
(200, 1, 664, NULL, 'Hey du alter Eis-Schleck-Rakete! 🍦🚀\nDas Bild sieht super aus. \nWillst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁\nDanach beginnt das Voting', '2026-03-08 05:52:06', NULL, NULL),
(201, 1, 761, NULL, 'Das Bild sieht super aus. \nWillst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\nDu hattest bei der letzten Challenge ja schon fast gewonnen 😁 \n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁\nDanach beginnt das Voting', '2026-03-08 05:53:48', NULL, NULL),
(202, 1, 542, NULL, 'Hey du alter Eis-Schleck-Rakete! 🍦🚀\nDas Bild sieht super aus. \nWillst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁\nDanach beginnt das Voting', '2026-03-08 05:54:10', NULL, NULL),
(203, 1, 840, NULL, 'Hey herzlich willkommen auf der Ice-App 🫶🏼🍦 \nDas Eis sieht wirklich mega lecker aus 😍 \n\nMagst du es vielleicht bei der Geburtstags-Fotochallenge einreichen? Ich denke das hat ganz gute Chancen 😁', '2026-03-08 05:56:20', NULL, NULL),
(204, 1, 829, NULL, 'Mega cool, der erste Check-in in Usbekistan 🇺🇿💯\nMagst du das Bild vielleicht gleich noch bei der Geburtstags-Fotochallenge einreichen? 😁', '2026-03-08 05:59:26', NULL, NULL),
(205, 1, 816, NULL, 'Das sieht einfach mega lecker aus 😍😋 \n\nMagst du das vielleicht bei der Geburtstags-Fotochallenge einreichen?\n\nBis zum 14 März kann jeder Nutzer bis zu 3 Bilder einreichen. 😁\nDanach beginnt das Voting, ich denke das Bild hätte ganz gute Chancen. 🤔', '2026-03-08 06:01:23', NULL, NULL),
(206, 125, 761, NULL, 'Done ✅️ Da bin ich doch direkt wieder mit am Start 🤩', '2026-03-08 10:21:42', NULL, NULL),
(207, 1, 761, NULL, 'Sehr nice, ich wusste auf dich ist verlass! Dann viel Erfolg schon mal!👍', '2026-03-08 10:26:22', NULL, NULL),
(208, 1, 841, NULL, 'Hey, herzlich willkommen (zurück) auf der Ice-App! 😁\nSchön dass du dabei bist und deinen ersten Check-in gemacht hast!', '2026-03-08 10:33:06', NULL, NULL),
(209, 125, 761, NULL, '😅 Dankeschön!', '2026-03-08 10:53:56', NULL, NULL),
(210, 1, 843, NULL, 'Da würde also auch bei dir die Eis-Saison 2026 eingeleutet, sehr gut 😎🍨', '2026-03-08 14:15:14', NULL, NULL),
(211, 118, 844, NULL, 'Gelatoride! 🥰', '2026-03-08 15:44:20', NULL, NULL),
(212, 53, 835, NULL, 'Oh ja, mein Lieblingsbäcker steht auch noch auf der ToDo', '2026-03-09 15:25:57', NULL, NULL),
(213, 1, 835, NULL, 'Vielleicht ja am 16. Mai zur Eis-Tour.\nAber psscht Spoiler 🤫', '2026-03-09 16:13:59', NULL, NULL),
(214, 1, 850, NULL, 'Da wird ja heute ordentlich Eis geschleckert 😂😋\nAber sind das wirklich 5 Kugeln in dem Becher? 😵‍💫😅', '2026-03-09 16:14:59', NULL, NULL),
(215, 158, 829, NULL, 'Klaro :)', '2026-03-09 19:06:29', NULL, NULL),
(216, 19, 853, NULL, 'Ankündigung vom Samstag für einen baldigen Besuch direkt in die Tat umgesetzt 👍\nSofteis gab es noch nicht, oder?', '2026-03-10 15:28:21', NULL, NULL),
(217, 1, 853, NULL, 'Na klar 😁👍🏼\nMeine daily Challenge hatte es eh zufällig für die Eisdiele generiert 😁\nNein Softeis gab es noch nicht.\n\nAber waren ordentlich viele Gäste dort.', '2026-03-10 16:13:28', NULL, NULL),
(218, 19, 853, NULL, 'Schade mit dem Softeis, aber schön dass es gut besucht ist. War Samstag Nachmittag bei meinem Besuch auch schon gut besucht. \nWenn du wieder mal in Hohenstein ein Eis isst sag bescheid, vielleicht klappt es ja mit einem gemeinsamen Check-in 😅', '2026-03-10 16:26:45', NULL, NULL),
(219, 1, 853, NULL, 'Ja das mach ich 😊\nDu kannst natürlich auch gerne Bescheid geben wenn du Richtung Chemnitz mal ein Eis essen bist 😁', '2026-03-10 18:16:11', NULL, NULL),
(220, 1, 852, NULL, 'Hey, super cool dich in zur Eis-Saison 2026 auf der Ice-App begrüßen zu können! 😊', '2026-03-10 20:48:57', NULL, NULL),
(221, 1, 851, NULL, 'Hey, cool dich mal wieder auf der Ice-App zu sehen 😊\n\nsieht auf jeden Fall sehr lecker was es bei euch gab, ein scheinbar guter Start in die Eis-Saison 2026! :D', '2026-03-10 20:50:18', NULL, NULL),
(222, 1, 858, NULL, 'Ja Ackermanns Eiscafé ist für Chemnitz ein echter Geheimtipp 😎', '2026-03-10 21:11:02', NULL, NULL);
